def _resolve_summary_openai_api_key(settings: Any) -> str:
    """Resolve OpenAI API key for runtime summary generation.

    This guards against stale cached settings objects by re-checking runtime env vars.
    """
    configured = str(getattr(settings, "openai_api_key", "") or "").strip()
    if configured:
        return configured

    for env_name in ("OPENAI_API_KEY", "OPENAI-API-KEY"):
        candidate = str(os.getenv(env_name, "") or "").strip()
        if candidate:
            try:
                settings.openai_api_key = candidate
            except Exception:  # noqa: BLE001
                pass
            return candidate

    return ""


def _extract_word_count_control(text: str) -> Tuple[str, Optional[int]]:
    """Extract an optional model-reported word count control token.

    Some prompts ask the model to append a line like `WORD_COUNT: 1234`.
    We return the text with that token stripped and the parsed count.
    """
    if not text:
        return text, None

    match = re.search(r"\bWORD[_\s]*COUNT\s*[:=]\s*(\d{1,6})\b", text)
    if not match:
        return text, None

    reported: Optional[int]
    try:
        reported = int(match.group(1))
    except (TypeError, ValueError):
        reported = None

    cleaned = re.sub(r"\bWORD[_\s]*COUNT\s*[:=]\s*\d{1,6}\b", "", text).strip()
    return cleaned, reported


def _normalize_casing(text: str) -> str:
    """Reduce shouty ALL-CAPS body text without touching headings."""
    if not text:
        return text

    lines = text.splitlines()
    out: List[str] = []
    for line in lines:
        stripped = line.strip()
        if not stripped:
            out.append(line)
            continue
        if stripped.startswith("#"):
            out.append(line)
            continue
        # Preserve parser markers exactly; these are consumed by the frontend grid parser.
        _marker_candidate = re.sub(r"[.\s]+$", "", stripped).upper()
        if _marker_candidate in {"DATA_GRID_START", "DATA_GRID_END"}:
            out.append(_marker_candidate)
            continue

        letters = [c for c in stripped if c.isalpha()]
        if not letters:
            out.append(line)
            continue

        upper_letters = sum(1 for c in letters if c.isupper())
        upper_ratio = upper_letters / max(1, len(letters))
        if upper_ratio >= 0.9 and len(letters) >= 12:
            lowered = stripped.lower()
            lowered = lowered[:1].upper() + lowered[1:]
            out.append(lowered)
        else:
            out.append(line)

    return "\n".join(out)


def _summary_output_format_for_target(target_length: Optional[int]) -> str:
    """Classify output format by requested target length."""
    if target_length and int(target_length) <= MICRO_PLAINTEXT_SUMMARY_MAX_TARGET_WORDS:
        return "plain_text_micro"
    return "markdown_sectioned"


def _is_micro_plaintext_target(target_length: Optional[int]) -> bool:
    return _summary_output_format_for_target(target_length) == "plain_text_micro"


def _is_short_form_sectioned_target(target_length: Optional[int]) -> bool:
    if _is_micro_plaintext_target(target_length):
        return False
    try:
        target = int(target_length or 0)
    except (TypeError, ValueError):
        return False
    return (
        int(SHORT_FORM_SECTIONED_TARGET_MIN_WORDS)
        <= target
        < int(SHORT_FORM_SECTIONED_TARGET_MAX_WORDS)
    )


def _is_short_mid_precision_target(target_length: Optional[int]) -> bool:
    """Return True for the full sectioned short/mid precision range [300, 1500)."""
    return _is_short_form_sectioned_target(target_length)


def _is_short_quality_sensitive_target(target_length: Optional[int]) -> bool:
    if not _is_short_mid_precision_target(target_length):
        return False
    try:
        return int(target_length or 0) <= 1200
    except (TypeError, ValueError):
        return False


def _is_explicit_short_mid_precision_target(
    *,
    target_length: Optional[int],
    explicit_target_requested: bool,
) -> bool:
    if not explicit_target_requested:
        return False
    return _is_short_mid_precision_target(target_length)


def _requires_section_balance_contract(
    *,
    target_length: Optional[int],
    explicit_target_requested: bool,
    v2_enabled: bool,
) -> bool:
    """Determine when section-balance validation is mandatory.

    Keep existing v2/long-form behavior unchanged, and additionally require
    section-balance checks for explicit short/mid precision requests.
    """
    if not target_length or _is_micro_plaintext_target(target_length):
        return False
    if v2_enabled:
        return True
    return _is_explicit_short_mid_precision_target(
        target_length=target_length,
        explicit_target_requested=explicit_target_requested,
    )


def _build_micro_plaintext_summary_prompt(
    *,
    identity_block: str,
    company_name: str,
    ticker: str,
    filing_type: str,
    filing_date: str,
    tone: str,
    detail_level: str,
    output_style: str,
    target_length: int,
    context_excerpt: str,
    truncated_note: str,
    financial_snapshot: str,
    metrics_lines: str,
    prior_period_delta_block: str,
    risk_factors_block: str,
    preference_block: str,
    company_profile_block: str = "",
    company_research_block_placeholder: str = "__COMPANY_RESEARCH_BLOCK__",
) -> str:
    """Build a compact one-shot prompt for tiny exact-length summaries."""
    return f"""
{identity_block}
Write a single-line investment summary for {company_name} ({ticker or "N/A"}) based on this {filing_type} filed {filing_date}.
{company_profile_block}
{company_research_block_placeholder}

TARGET CONTRACT (HARD):
- Output EXACTLY {int(target_length)} words.
- One line only. Plain text only. No markdown headings, bullets, or labels.
- End with final punctuation.
- Decision-oriented verdict plus one company-specific current-state driver and one forward-looking implication.
- No repeated words, no filler padding, no counting commentary, no self-referential text.
- Do not mention instructions or word counts.
- If evidence is mixed, still choose a clear directional posture and name the key constraint.
- Favor business-model-specific drivers, management outlook, or filing-period-specific developments over generic margin/cash/risk triads.

STYLE:
- Tone: {tone.title()}
- Detail Level: {detail_level.title()} (compress to essentials only)
- Output Style: {output_style.title()} (but still plain text single line)

{preference_block}

CONTEXT:
{context_excerpt}{truncated_note}

FINANCIAL SNAPSHOT (Reference):
{financial_snapshot}

KEY METRICS (Reference):
{metrics_lines}
{prior_period_delta_block}
{risk_factors_block}

Return only the final {int(target_length)}-word summary line.
""".strip()


def _make_micro_plaintext_summary_validator(
    target_length: int,
) -> Callable[[str], Optional[str]]:
    """Validate tiny one-line summaries for exact word count and anti-slop quality."""

    def _validator(text: str) -> Optional[str]:
        report = validate_summary_contract(
            text or "",
            target_words=max(1, int(target_length)),
            require_single_line=True,
            forbid_markdown_headings=True,
        )
        reasons = list(report.get("reasons") or [])
        if not reasons:
            return None
        return "micro_summary_contract_failed: " + ", ".join(str(r) for r in reasons)

    return _validator


