def _repair_section_management_voice_from_snippets(
    summary_text: str,
    *,
    section_title: str,
    filing_language_snippets: str,
    target_length: Optional[int] = None,
    action_name: str,
) -> Tuple[str, Dict[str, Any]]:
    text = (summary_text or "").strip()
    info: Dict[str, Any] = {"changed": False, "applied": False, "action": None}
    if not text:
        return summary_text, info

    body = _extract_markdown_section_body(text, section_title)
    if not body or _has_management_voice_markers(
        body, filing_language_snippets=filing_language_snippets
    ):
        return summary_text, info

    candidates = _management_snippet_candidates(filing_language_snippets)

    rebuilt = body
    if candidates:
        quote_policy = _summary_quote_policy_for_target_length(target_length)
        existing_quote_count = _count_direct_quotes_in_section(
            text, "Executive Summary"
        ) + _count_direct_quotes_in_section(text, "Management Discussion & Analysis")
        use_direct_quote = existing_quote_count < int(
            quote_policy.get("max_quotes", 0) or 0
        )
        chosen = candidates[0]
        prefix = (
            f'Management noted, "{chosen.rstrip(".!?").strip()}."'
            if use_direct_quote
            else _management_attribution_sentence_from_candidate(chosen)
        )
        prefix = _cleanup_sentence_artifacts(prefix)
        if not prefix:
            return summary_text, info
        rebuilt = f"{prefix} {body}".strip()
    else:
        source_sentence, attributed_sentence = (
            _select_management_voice_sentence_from_mdna_body(body)
        )
        attributed_sentence = _cleanup_sentence_artifacts(attributed_sentence)
        if not attributed_sentence:
            return summary_text, info
        if source_sentence and source_sentence in body:
            rebuilt = body.replace(source_sentence, attributed_sentence, 1).strip()
        else:
            rebuilt = f"{attributed_sentence} {body}".strip()

    rebuilt = _cleanup_sentence_artifacts(rebuilt)
    rebuilt = _validate_complete_sentences(rebuilt)
    if rebuilt and rebuilt[-1] not in ".!?":
        rebuilt += "."
    if rebuilt == body:
        return summary_text, info

    updated = _replace_markdown_section_body(
        text, section_title, rebuilt
    )
    if updated == text:
        return summary_text, info

    info["changed"] = True
    info["applied"] = True
    info["action"] = action_name
    return updated, info


def _repair_timeout_editorial_contract_gaps(
    summary_text: str,
    *,
    validation: "SummaryValidationReport",
    target_length: Optional[int],
    section_budgets: Dict[str, int],
    filing_language_snippets: str,
    risk_factors_excerpt: str,
    calculated_metrics: Optional[Dict[str, Any]],
    health_score_data: Optional[Dict[str, Any]],
    generation_stats: Optional[Dict[str, Any]] = None,
) -> Tuple[str, Dict[str, Any]]:
    text = (summary_text or "").strip()
    info: Dict[str, Any] = {"changed": False, "applied": False, "actions": []}
    if not text:
        return summary_text, info

    failure_codes = {
        str(failure.code or "").strip()
        for failure in list(getattr(validation, "section_failures", []) or [])
        if str(failure.code or "").strip()
    }
    validation_flags = _issue_flags_from_validation_report(validation)
    timeout_quality_profile = SummaryFlowQualityProfile(
        max_same_opening=2,
        max_sections_per_repeated_number=2,
        max_sections_per_theme=(
            4 if _is_long_form_target(target_length) else 3
        ),
        closing_numeric_anchor_cap=1 if (target_length or 0) < 600 else 2,
    )

    if validation_flags.get("management_voice_issue") or (
        "insufficient_management_voice" in failure_codes
    ):
        text, exec_voice_info = _repair_executive_summary_management_voice_from_snippets(
            text,
            filing_language_snippets=filing_language_snippets,
            target_length=target_length,
        )
        if exec_voice_info.get("applied"):
            info["changed"] = True
            info["applied"] = True
            info["actions"].append(
                str(
                    exec_voice_info.get("action")
                    or "executive_summary_management_voice_repair"
                )
            )

        text, voice_info = _repair_mdna_management_voice_from_snippets(
            text,
            filing_language_snippets=filing_language_snippets,
            target_length=target_length,
        )
        if voice_info.get("applied"):
            info["changed"] = True
            info["applied"] = True
            info["actions"].append(str(voice_info.get("action") or "mdna_management_voice_repair"))

        text, closing_voice_info = _repair_closing_takeaway_management_voice_from_snippets(
            text,
            filing_language_snippets=filing_language_snippets,
            target_length=target_length,
        )
        if closing_voice_info.get("applied"):
            info["changed"] = True
            info["applied"] = True
            info["actions"].append(
                str(
                    closing_voice_info.get("action")
                    or "closing_takeaway_management_voice_repair"
                )
            )

        if (filing_language_snippets or "").strip():
            quote_policy = _summary_quote_policy_for_target_length(target_length)
            rebalanced = _rebalance_contract_quotes(
                text,
                filing_language_snippets=filing_language_snippets,
                min_required_quotes=quote_policy["min_quotes"],
                max_allowed_quotes=quote_policy["max_quotes"],
            )
            if rebalanced != text:
                text = rebalanced
                info["changed"] = True
                info["applied"] = True
                info["actions"].append("management_voice_quote_rebalance")

    if validation_flags.get("bridge_issue") and "## Financial Health Rating" in text:
        bridged = _ensure_health_to_exec_bridge(text, target_length=target_length)
        if bridged != text:
            text = bridged
            info["changed"] = True
            info["applied"] = True
            info["actions"].append("health_to_exec_bridge_repair")

    if _has_hard_risk_issue(validation_flags) or (
        {"risk_schema", "risk_specificity"} & failure_codes
    ):
        risk_body = _extract_markdown_section_body(text, "Risk Factors") or ""
        risk_budget_words = int(section_budgets.get("Risk Factors", 0) or 0)
        if risk_body.strip() and risk_budget_words > 0:
            normalized_risk_body, risk_info = _normalize_risk_factors_section_body(
                risk_body,
                risk_budget_words=risk_budget_words,
                risk_factors_excerpt=risk_factors_excerpt,
                calculated_metrics=calculated_metrics,
                health_score_data=health_score_data,
                synthesize_risk_factors_addendum_fn=(
                    _synthesize_risk_factors_addendum
                    if "_synthesize_risk_factors_addendum" in globals()
                    else None
                ),
            )
            if normalized_risk_body and normalized_risk_body.strip() != risk_body.strip():
                text = _replace_markdown_section_body(
                    text, "Risk Factors", normalized_risk_body
                )
                info["changed"] = True
                info["applied"] = True
                info["actions"].append("risk_factor_normalization_repair")

    if validation_flags.get("needs_editorial_deterministic_repair") or (
        "cross_section_dollars" in failure_codes
    ):
        text, editorial_info = _apply_editorial_contract_repairs(
            text,
            target_length=target_length,
            include_health_rating="## Financial Health Rating" in text,
            quality_profile=timeout_quality_profile,
            missing_requirements=_validation_failure_messages(validation),
            issue_flags=validation_flags,
            generation_stats=generation_stats,
        )
        if editorial_info.get("changed"):
            info["changed"] = True
            info["applied"] = True
            info["actions"].extend(list(editorial_info.get("actions") or []))

    if info.get("applied") and target_length:
        text = _ensure_final_strict_word_band(
            text,
            int(target_length),
            include_health_rating="## Financial Health Rating" in text,
            tolerance=_effective_word_band_tolerance(target_length),
            generation_stats=generation_stats,
            allow_padding=False,
        )
        text = _enforce_whitespace_word_band(
            text,
            int(target_length),
            tolerance=_effective_word_band_tolerance(target_length),
            allow_padding=False,
            dedupe=True,
        )
        if generation_stats is not None and info.get("actions"):
            generation_stats.setdefault("timeout_editorial_contract_repairs", []).extend(
                list(info["actions"])
            )

    return text, info


_DIRECT_QUOTE_SPAN_RE = re.compile(r"[“\"][^“”\"\n]{1,400}[”\"]")


def _strip_direct_quote_spans(text: str) -> str:
    if not text:
        return ""
    cleaned = _DIRECT_QUOTE_SPAN_RE.sub("", text)
    cleaned = re.sub(r"\s+([,.;:!?])", r"\1", cleaned)
    cleaned = re.sub(r"[ \t]{2,}", " ", cleaned)
    cleaned = re.sub(r"\n{3,}", "\n\n", cleaned)
    return cleaned.strip()


def _count_numeric_tokens(text: str) -> int:
    if not text:
        return 0
    # Ignore numbers inside direct quotes so editorial repair passes do not get
    # punished for preserving verbatim filing language.
    unquoted = _strip_direct_quote_spans(text)
    # Tokens that contain at least one digit (captures FY24, 10-K, $9.2B, 1.5x, 36.2%, etc.)
    return len(re.findall(r"\b[\w$€£]*\d[\w%/.\-]*\b", unquoted))


@dataclass(frozen=True)
class SummaryFlowQualityProfile:
    max_same_opening: int = 3
    max_sections_per_repeated_number: int = 3
    max_sections_per_theme: int = 4
    closing_numeric_anchor_cap: Optional[int] = None


_SUMMARY_NARRATIVE_REPETITION_SECTIONS: Tuple[str, ...] = (
    "Financial Health Rating",
    "Executive Summary",
    "Financial Performance",
    "Management Discussion & Analysis",
    "Risk Factors",
    "Closing Takeaway",
)

_SUMMARY_REPEATED_FIGURE_RE = re.compile(r"\$[\d,.]+\s*[BMKTbmkt]?\b|\d+\.?\d*\s*%")

_SUMMARY_THEME_PATTERNS: Dict[str, re.Pattern[str]] = {
    "cash conversion": re.compile(
        r"cash\s+(?:conversion|converts?|converting)", re.IGNORECASE
    ),
    "free cash flow": re.compile(r"free\s+cash\s+flow|FCF", re.IGNORECASE),
    "margin pressure": re.compile(
        r"margin\s+(?:pressure|compression|compresses?|erodes?)", re.IGNORECASE
    ),
    "reinvestment": re.compile(
        r"reinvestment|capex\s+(?:intensity|cycle|rising)", re.IGNORECASE
    ),
    "balance sheet flexibility": re.compile(
        r"balance[- ]sheet\s+(?:flexibility|risk|strength|buffer)", re.IGNORECASE
    ),
    "working capital": re.compile(
        r"working[- ]capital\s+(?:timing|normaliz|inflat|depress)", re.IGNORECASE
    ),
    "below the line": re.compile(
        r"below[- ]the[- ]line|non[- ]operating\s+(?:items?|support|income)",
        re.IGNORECASE,
    ),
    "earnings quality": re.compile(
        r"earnings?\s+quality|operating\s+vs\.?\s+net", re.IGNORECASE
    ),
}

_SUMMARY_QUESTION_FRAMING_PATTERNS: Tuple[re.Pattern[str], ...] = (
    re.compile(
        r"\b(?:that\s+sets\s+up\s+)?(?:the\s+)?(?:core|key|central|main|operating|execution)\s+question\s+(?:is|remains|becomes)?\s*whether\b",
        re.IGNORECASE,
    ),
    re.compile(
        r"\bthe\s+central\s+tension\s+(?:is|remains)\s+whether\b",
        re.IGNORECASE,
    ),
    re.compile(
        r"\bthe\s+key\s+issue\s+(?:is|remains)\s+whether\b",
        re.IGNORECASE,
    ),
)


def _normalize_repeated_figure_token(fig: str) -> str:
    return re.sub(r"\s+", "", str(fig or "").strip().lower())


def _numbers_discipline_caps(
    target_length: Optional[int],
    *,
    closing_numeric_cap_override: Optional[int] = None,
) -> Dict[str, int]:
    """Shared caps for narrative numeric density (used by validators + repairs)."""
    long_form = _is_long_form_target(target_length)
    short_quality = _is_short_quality_sensitive_target(target_length)
    higher_detail = bool((target_length or 0) >= 600)
    if long_form:
        caps = {
            "Executive Summary": 3,
            "Financial Performance": 7,
            "Management Discussion & Analysis": 3,
            "Risk Factors": 2,
            "Closing Takeaway": 2,
        }
    elif short_quality:
        caps = {
            "Executive Summary": 2,
            "Financial Performance": 4 if higher_detail else 3,
            "Management Discussion & Analysis": 2,
            "Risk Factors": 2,
            "Closing Takeaway": 1,
        }
    else:
        caps = {
            "Executive Summary": 3 if higher_detail else 2,
            "Financial Performance": 7 if higher_detail else 5,
            "Management Discussion & Analysis": 3 if higher_detail else 2,
            "Risk Factors": 2,
            "Closing Takeaway": 2 if higher_detail else 1,
        }
    if closing_numeric_cap_override is not None:
        caps["Closing Takeaway"] = max(1, int(closing_numeric_cap_override))
    return caps


def _build_summary_quality_profile(
    *,
    target_length: Optional[int],
    is_flash_model: bool,
    flash_first_enabled: bool,
) -> SummaryFlowQualityProfile:
    if _is_short_quality_sensitive_target(target_length):
        return SummaryFlowQualityProfile(
            max_same_opening=2,
            max_sections_per_repeated_number=2,
            max_sections_per_theme=2,
            closing_numeric_anchor_cap=1 if (target_length or 0) < 600 else 2,
        )
    if not (flash_first_enabled and is_flash_model):
        return SummaryFlowQualityProfile()

    is_long_form = (target_length or 0) >= 1500
    base_closing_cap = 4 if (target_length or 0) >= 600 else 3
    return SummaryFlowQualityProfile(
        max_same_opening=2,
        max_sections_per_repeated_number=3 if is_long_form else 2,
        max_sections_per_theme=4 if is_long_form else 3,
        closing_numeric_anchor_cap=max(1, base_closing_cap - 1),
    )


def _make_numbers_discipline_validator(
    target_length: Optional[int],
    *,
    closing_numeric_cap_override: Optional[int] = None,
) -> Callable[[str], Optional[str]]:
    # Keep narrative sections argument-first, not inventory-first.
    # Tightened caps to force qualitative writing — numbers support, not structure.
    caps = _numbers_discipline_caps(
        target_length,
        closing_numeric_cap_override=closing_numeric_cap_override,
    )
    max_exec = int(caps.get("Executive Summary", 4))
    max_perf = int(caps.get("Financial Performance", 7))
    max_mdna = int(caps.get("Management Discussion & Analysis", 4))
    max_risk = int(caps.get("Risk Factors", 3))
    max_closing = int(caps.get("Closing Takeaway", 2))

    def _validator(text: str) -> Optional[str]:
        exec_body = _extract_markdown_section_body(text, "Executive Summary")
        if exec_body:
            exec_nums = _count_numeric_tokens(exec_body)
            if exec_nums > max_exec:
                return (
                    f"Numbers discipline: Executive Summary is too numeric ({exec_nums} numeric tokens). "
                    "Keep it mostly qualitative with only 1-2 anchor figures; move dense metrics to Financial Performance / Key Metrics."
                )

        perf_body = _extract_markdown_section_body(text, "Financial Performance")
        if perf_body:
            perf_nums = _count_numeric_tokens(perf_body)
            if perf_nums > max_perf:
                return (
                    f"Numbers discipline: Financial Performance is too numeric ({perf_nums} numeric tokens). "
                    "Keep only the 3-5 most decision-relevant figures in prose and move the rest to Key Metrics."
                )

        mdna_body = _extract_markdown_section_body(
            text, "Management Discussion & Analysis"
        )
        if mdna_body:
            mdna_nums = _count_numeric_tokens(mdna_body)
            if mdna_nums > max_mdna:
                return (
                    f"Numbers discipline: Management Discussion & Analysis is too numeric ({mdna_nums} numeric tokens). "
                    "Keep this section strategic and mechanism-first, with only a few anchor numbers."
                )

        risk_body = _extract_markdown_section_body(text, "Risk Factors")
        if risk_body:
            risk_nums = _count_numeric_tokens(risk_body)
            if risk_nums > max_risk:
                return (
                    f"Numbers discipline: Risk Factors is too numeric ({risk_nums} numeric tokens). "
                    "Keep risk discussion mechanism-first (business exposure and transmission path), with numbers as optional support."
                )

        closing_body = _extract_markdown_section_body(text, "Closing Takeaway")
        if closing_body:
            closing_nums = _count_numeric_tokens(closing_body)
            if closing_nums > max_closing:
                return (
                    f"Numbers discipline: Closing Takeaway is too numeric ({closing_nums} numeric tokens). "
                    "Synthesize the narrative and keep numbers minimal; focus on verdict + what would change the view."
                )

        return None

    return _validator


def _make_metric_priority_validator(
    target_length: Optional[int],
) -> Callable[[str], Optional[str]]:
    """Keep narrative sections focused on a small set of primary drivers."""

    higher_detail = bool((target_length or 0) >= 600)
    max_unique_numbers: Dict[str, int] = {
        "Executive Summary": 3 if higher_detail else 2,
        "Financial Performance": 6 if higher_detail else 5,
        "Management Discussion & Analysis": 4 if higher_detail else 3,
        "Risk Factors": 3 if higher_detail else 2,
        "Closing Takeaway": 2 if higher_detail else 1,
    }

    metric_terms: Dict[str, re.Pattern[str]] = {
        "free_cash_flow": re.compile(r"\bfree\s+cash\s+flow|fcf\b", re.IGNORECASE),
        "operating_margin": re.compile(r"\boperating\s+margin\b", re.IGNORECASE),
        "cash_conversion": re.compile(
            r"\bcash\s+conversion\b|\bocf\s*(?:to|→|-)\s*fcf\b", re.IGNORECASE
        ),
        "revenue": re.compile(r"\brevenue\b", re.IGNORECASE),
        "operating_cash_flow": re.compile(
            r"\boperating\s+cash\s+flow\b|\bocf\b", re.IGNORECASE
        ),
        "net_margin": re.compile(r"\bnet\s+margin\b", re.IGNORECASE),
        "liquidity": re.compile(
            r"\bcurrent\s+ratio\b|\bcash\b|\bliquidity\b", re.IGNORECASE
        ),
        "leverage": re.compile(
            r"\bdebt\b|\bliabilit(?:y|ies)\b|\bleverage\b", re.IGNORECASE
        ),
    }

    echo_patterns: Dict[str, re.Pattern[str]] = {
        "thesis_stays_grounded": re.compile(
            r"\bthe thesis stays grounded in\b", re.IGNORECASE
        ),
        "clearest_quantitative_read": re.compile(
            r"\bthe clearest quantitative read on this period\b", re.IGNORECASE
        ),
        "easier_to_underwrite": re.compile(
            r"\b(?:performance quality|capital-allocation credibility)\s+is easier to underwrite\b",
            re.IGNORECASE,
        ),
        "execution_judged_against": re.compile(
            r"\bexecution durability should be judged against\b", re.IGNORECASE
        ),
        "risk_severity_increases": re.compile(
            r"\brisk severity increases(?: quickly)? if\b", re.IGNORECASE
        ),
        "stance_changes_only_if": re.compile(
            r"\bthe stance should change only if\b", re.IGNORECASE
        ),
    }

    figure_re = re.compile(r"\$[\d,.]+\s*[BMKTbmkt]?\b|\d+\.?\d*\s*(?:%|x|pp)\b")

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        for section, limit in max_unique_numbers.items():
            body = _extract_markdown_section_body(text, section)
            if not body:
                continue

            # Prioritize a small set of numbers in narrative prose.
            unique_numbers = {
                re.sub(r"\s+", "", m.group(0).lower())
                for m in figure_re.finditer(body)
                if (m.group(0) or "").strip()
            }
            if len(unique_numbers) > int(limit):
                return (
                    f"Metric priority drift: {section} references {len(unique_numbers)} distinct numeric figures. "
                    f"Keep this section to at most {limit} anchor figures and move the rest to Key Metrics."
                )

            # Executive + Closing should communicate hierarchy, not inventory.
            if section in {"Executive Summary", "Closing Takeaway"}:
                mentioned = {
                    name for name, pat in metric_terms.items() if pat.search(body or "")
                }
                if len(mentioned) > 3:
                    return (
                        f"Metric hierarchy drift in {section}: {len(mentioned)} driver classes are treated as primary. "
                        "Prioritize at most 3 core drivers and treat all others as supporting evidence."
                    )

            for label, pattern in echo_patterns.items():
                count = len(pattern.findall(body))
                if count > 1:
                    pretty = label.replace("_", " ")
                    return (
                        f"Metric echo detected in {section}: pattern '{pretty}' repeats {count} times. "
                        "State each driver once, then advance the analysis."
                    )

        return None

    return _validator


def _make_verbatim_repetition_validator() -> Callable[[str], Optional[str]]:
    """
    Reject memos with repeated sentences/near-identical sentences (a common failure mode
    when the model pads word count by rephrasing the same point).
    """

    def _normalize(sentence: str) -> str:
        cleaned = (sentence or "").strip()
        cleaned = cleaned.replace("’", "'").replace("“", '"').replace("”", '"')
        cleaned = re.sub(r"\s+", " ", cleaned)
        cleaned = cleaned.lower()
        cleaned = re.sub(r"[^a-z0-9%$ ]+", "", cleaned)
        cleaned = re.sub(r"\s+", " ", cleaned).strip()
        return cleaned

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        bodies: List[str] = []
        for title in (
            "Financial Health Rating",
            "Executive Summary",
            "Financial Performance",
            "Management Discussion & Analysis",
            "Risk Factors",
            "Closing Takeaway",
        ):
            body = _extract_markdown_section_body(text, title)
            if body:
                bodies.append(body)

        joined = "\n".join(bodies)
        joined = re.sub(r"^\s*WORD COUNT:\s*\d+\s*$", "", joined, flags=re.MULTILINE)

        sentences = re.split(r"(?<=[.!?])\s+", joined)
        counts: Dict[str, int] = {}
        samples: Dict[str, str] = {}
        for sentence in sentences:
            normalized = _normalize(sentence)
            if not normalized:
                continue
            # Skip short sentences; allow a small amount of unavoidable repetition.
            if len(normalized) < 70 or len(normalized.split()) < 10:
                continue
            counts[normalized] = counts.get(normalized, 0) + 1
            samples.setdefault(normalized, sentence.strip())

        repeated = [k for k, v in counts.items() if v >= 2]
        if repeated:
            sample = samples[repeated[0]]
            sample = re.sub(r"\s+", " ", sample).strip()
            return (
                "Verbatim repetition detected (same sentence appears multiple times). "
                f"Remove repeats and keep each idea once per section. Example repeated sentence: '{sample[:140]}...'"
            )

        normalized_tail = _normalize(joined)
        tokens = [token for token in normalized_tail.split() if token]
        for span in range(8, 3, -1):
            max_start = len(tokens) - (span * 3) + 1
            if max_start <= 0:
                continue
            for start in range(max_start):
                clause = tokens[start : start + span]
                if len(set(clause)) < 3:
                    continue
                repeats = 1
                cursor = start + span
                while (
                    cursor + span <= len(tokens)
                    and tokens[cursor : cursor + span] == clause
                ):
                    repeats += 1
                    cursor += span
                if repeats >= 3:
                    sample = " ".join(clause).strip()
                    return (
                        "Verbatim repetition detected (repeated clause loop in narrative prose). "
                        f"Remove repeated tail padding. Example clause: '{sample[:120]}...'"
                    )

        return None

    return _validator


def _make_phrase_limits_validator() -> Callable[[str], Optional[str]]:
    """
    Reject common "manifesto"/definition loops that hurt readability.
    These are intentionally narrow (specific phrases) to avoid blocking legitimate analysis.
    """

    def _normalize(text: str) -> str:
        lowered = (text or "").lower()
        lowered = lowered.replace("’", "'")
        lowered = re.sub(r"[^a-z0-9%$ ]+", " ", lowered)
        lowered = re.sub(r"\s+", " ", lowered).strip()
        return lowered

    # pattern -> max allowed count
    limits: Dict[str, int] = {
        "management execution drivers remain the key watchpoint": 0,
        "reported financials lack sufficient detail on revenue margin and cash flow": 0,
        "future filings clarify the earnings to cash bridge": 0,
        # Definitions / meta-commentary (forbidden)
        "free cash flow is the difference": 0,
        "thesis reads best": 0,
        "this thesis reads": 0,
        "what i care about": 0,
        "i care about": 0,
        "i focus on": 0,
        "what i watch": 0,
        "i will be watching": 0,
        "falsify the thesis": 0,
        "falsifies the thesis": 0,
        "what would falsify": 0,
        # Monitoring-checklist patterns (cap or forbid)
        "track whether": 1,
        "watch whether": 1,
        "verify whether": 0,
        "monitor whether": 1,
        "additionally monitor": 0,
        "additionally track": 0,
        "additionally watch": 0,
        "additionally verify": 0,
        "also monitor": 1,
        "also track": 1,
        "also watch": 1,
        # Catchphrase spam (cap tightly)
        "margin for error": 1,
        "watch cash conversion": 1,
        "base case hold": 1,
        # Instruction-echo patterns (forbidden — these are internal directives, not analysis)
        "as instructed": 0,
        "per the guidelines": 0,
        "commentary not provided": 0,
        "not provided in the draft": 0,
        "the memo should": 0,
        "the analysis should": 0,
        "keep this section": 0,
        "each risk should map to": 0,
        "connect revenue trends to": 0,
        # Generic financial axioms that pad word count (cap tightly)
        "cash conversion can diverge": 0,
        "below the line support should not be treated": 0,
        "a strong quarter is more credible when": 0,
        "risk is asymmetric when": 1,
        "the dominant downside scenario": 1,
        "a credible risk write up": 0,
        "second order risks matter": 0,
        "the probability of outsized returns": 0,
        "provides the balance sheet backdrop": 0,
        "frames the margin for error": 1,
        "defines the upper bound of sustainable growth": 0,
        "the usual culprits": 0,
    }

    def _validator(text: str) -> Optional[str]:
        normalized = _normalize(text)
        for phrase, max_count in limits.items():
            count = normalized.count(phrase)
            if count > max_count:
                if max_count == 0:
                    return f"Forbidden phrase detected ('{phrase}'). Remove it entirely and rewrite without meta/definition filler."
                return (
                    f"Over-repetition detected: '{phrase}' appears {count} times. "
                    f"Cap it at {max_count} (introduce once, then move on)."
                )
        return None

    return _validator


def _make_instruction_leak_validator() -> Callable[[str], Optional[str]]:
    """Catch instruction-leak patterns that escaped prompt boundaries.

    These are phrases that belong to our system prompt or synthesizer
    coaching, not to the user-visible memo.  If any are detected, force
    a retry so the LLM rewrites without echoing its instructions.
    """

    _leak_patterns: List[re.Pattern[str]] = [
        re.compile(r"financial performance commentary not provided", re.IGNORECASE),
        re.compile(r"not provided in the draft", re.IGNORECASE),
        re.compile(r"commentary not provided", re.IGNORECASE),
        re.compile(r"keep this section concrete", re.IGNORECASE),
        re.compile(r"keep this section", re.IGNORECASE),
        re.compile(r"this section should\b", re.IGNORECASE),
        re.compile(r"each risk should map to", re.IGNORECASE),
        re.compile(r"as instructed", re.IGNORECASE),
        re.compile(r"per the guidelines", re.IGNORECASE),
        re.compile(r"the analysis should\b", re.IGNORECASE),
        re.compile(r"the memo should\b", re.IGNORECASE),
        re.compile(r"connect revenue trends to", re.IGNORECASE),
        re.compile(r"unit economics need to improve via", re.IGNORECASE),
        re.compile(r"reconciles KPI commentary", re.IGNORECASE),
        re.compile(
            r"add\s+revenue(?:/margin/cash\s*flow|,\s*margin,?\s*(?:and\s*)?cash\s*flow)",
            re.IGNORECASE,
        ),
        re.compile(r"(?:structure|flow) is mandatory", re.IGNORECASE),
        re.compile(r"suggested length:", re.IGNORECASE),
        re.compile(r"voice discipline:", re.IGNORECASE),
        re.compile(r"numbers discipline:", re.IGNORECASE),
    ]

    def _validator(text: str) -> Optional[str]:
        for pat in _leak_patterns:
            m = pat.search(text or "")
            if m:
                return (
                    f"Instruction leak detected ('{m.group()}'). "
                    "Rewrite the output without echoing any part of the instructions, "
                    "coaching language, or meta-commentary about your process."
                )
        return None

    return _validator


def _make_sentence_stem_repetition_validator(
    *,
    max_same_opening: int = 3,
) -> Callable[[str], Optional[str]]:
    """
    Detect "same sentence shape" repetition even when not verbatim.
    Heuristic: repeated leading word-stems across long sentences, plus
    per-section leading-word frequency checks to catch "If... If... If..." loops.
    """

    stopwords = {
        "the",
        "a",
        "an",
        "and",
        "or",
        "but",
        "so",
        "to",
        "of",
        "in",
        "on",
        "for",
        "with",
        "as",
        "at",
        "by",
        "from",
        "this",
        "that",
        "these",
        "those",
    }

    _SECTION_TITLES = (
        "Financial Health Rating",
        "Executive Summary",
        "Financial Performance",
        "Management Discussion & Analysis",
        "Risk Factors",
        "Closing Takeaway",
    )

    def _normalize(sentence: str) -> List[str]:
        cleaned = (sentence or "").lower()
        cleaned = (
            cleaned.replace("\u2019", "'").replace("\u201c", '"').replace("\u201d", '"')
        )
        cleaned = re.sub(r"[^a-z0-9 ]+", " ", cleaned)
        cleaned = re.sub(r"\s+", " ", cleaned).strip()
        words = [w for w in cleaned.split() if w and w not in stopwords]
        return words

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        # --- Check 1: per-section leading-word frequency ---
        for title in _SECTION_TITLES:
            body = _extract_markdown_section_body(text, title)
            if not body:
                continue
            # Strip markdown header lines before splitting into sentences
            # so that `##` is not counted as a leading word.
            body_lines = body.strip().splitlines()
            prose_lines = [ln for ln in body_lines if not re.match(r"^\s*#{1,6}", ln)]
            prose_body = "\n".join(prose_lines)
            section_sentences = [
                s.strip()
                for s in re.split(r"(?<=[.!?])\s+", prose_body)
                if s.strip() and len(s.split()) >= 6
            ]
            if len(section_sentences) < 5:
                continue
            leading_word_counts: Dict[str, int] = {}
            for s in section_sentences:
                first_word = s.split()[0].lower().rstrip(".,;:")
                if first_word.startswith("#") or first_word in stopwords:
                    continue
                leading_word_counts[first_word] = (
                    leading_word_counts.get(first_word, 0) + 1
                )
            for word, count in leading_word_counts.items():
                if count > int(max_same_opening):
                    return (
                        f"Leading-word repetition in {title}: {count} sentences start with '{word.capitalize()}'. "
                        "Vary sentence openings — do not begin more than 2 sentences per section with the same word."
                    )

        # --- Check 2: cross-section stem repetition (lowered from 3 → 2) ---
        bodies: List[str] = []
        for title in _SECTION_TITLES:
            body = _extract_markdown_section_body(text, title)
            if body:
                bodies.append(body)

        joined = "\n".join(bodies)
        joined = re.sub(r"^\s*WORD COUNT:\s*\d+\s*$", "", joined, flags=re.MULTILINE)
        joined = re.sub(r"^\s*#{1,6}\s+.*$", "", joined, flags=re.MULTILINE)

        sentences = re.split(r"(?<=[.!?])\s+", joined)
        counts: Dict[str, int] = {}
        samples: Dict[str, str] = {}
        for sentence in sentences:
            words = _normalize(sentence)
            if len(words) < 14:
                continue
            stem = " ".join(words[:8])
            if len(stem) < 25:
                continue
            counts[stem] = counts.get(stem, 0) + 1
            samples.setdefault(stem, sentence.strip())

        repeated = [k for k, v in counts.items() if v >= 2]
        if repeated:
            sample = re.sub(r"\s+", " ", samples[repeated[0]]).strip()
            return (
                "Repetition-by-structure detected (multiple long sentences start the same way). "
                f"Rewrite to avoid looping phrasing. Example: '{sample[:140]}...'"
            )
        return None

    return _validator


def _make_cross_section_number_repetition_validator(
    *,
    max_sections_per_figure: int = 3,
) -> Callable[[str], Optional[str]]:
    """Reject memos where the same narrative figure appears in too many sections."""

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        figure_section_map: Dict[str, set] = {}
        for section_title in _SUMMARY_NARRATIVE_REPETITION_SECTIONS:
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue
            figures = _SUMMARY_REPEATED_FIGURE_RE.findall(
                _strip_direct_quote_spans(body)
            )
            for fig in figures:
                norm = _normalize_repeated_figure_token(fig)
                if not norm:
                    continue
                figure_section_map.setdefault(norm, set()).add(section_title)

        overused = [
            (fig, sections)
            for fig, sections in figure_section_map.items()
            if len(sections) > int(max_sections_per_figure)
        ]
        if overused:
            worst_fig, worst_sections = max(overused, key=lambda x: len(x[1]))
            return (
                f"Number repetition across sections: '{worst_fig}' appears in {len(worst_sections)} sections. "
                "Use each specific figure in at most 2-3 sections; reference it by context elsewhere."
            )
        return None

    return _validator


def _company_specific_terms_from_context(*sources: Optional[str]) -> Set[str]:
    stop_words = {
        "about",
        "after",
        "before",
        "between",
        "business",
        "capital",
        "cash",
        "company",
        "conversion",
        "could",
        "customer",
        "customers",
        "demand",
        "financial",
        "flow",
        "future",
        "growth",
        "guidance",
        "however",
        "industry",
        "liquidity",
        "management",
        "margin",
        "margins",
        "market",
        "period",
        "pricing",
        "quarter",
        "revenue",
        "risk",
        "section",
        "strategy",
        "through",
        "while",
        "would",
    }
    terms: Set[str] = set()
    for source in sources:
        normalized = " ".join((source or "").split()).lower()
        for token in re.findall(r"[a-z][a-z0-9&.-]{3,}", normalized):
            if token in stop_words:
                continue
            terms.add(token)
    return terms


def _make_generic_filler_validator(
    *,
    context_texts: Optional[List[str]] = None,
) -> Callable[[str], Optional[str]]:
    """Reject sections dominated by generic financial axioms that apply to any company."""

    # Patterns that signal generic textbook filler rather than company-specific analysis
    _GENERIC_PATTERNS = [
        re.compile(
            r"^if\s+(cash\s+conversion|margins?\s+move|free\s+cash\s+flow|operating\s+cash\s+flow|revenue\s+rises?|growth\s+slow)",
            re.IGNORECASE,
        ),
        re.compile(
            r"^(a|the)\s+(strong|weak|durable|credible)\s+(quarter|thesis|risk|position)\s+is\s+(more|most|best|only)\b",
            re.IGNORECASE,
        ),
        re.compile(
            r"^(margin|cash|balance.sheet|working.capital|risk)\s+(compression|pressure|risk|flexibility|structure)\s+is\s+(most|often|usually|secondary|best)\b",
            re.IGNORECASE,
        ),
        re.compile(
            r"^(when|if)\s+growth\s+(is\s+strong|slows?|weakens?),?\s+the\s+focus\s+is\b",
            re.IGNORECASE,
        ),
        re.compile(
            r"^(cash\s+conversion\s+can|below.the.line|second.order\s+risks?|a\s+widening\s+gap)\b",
            re.IGNORECASE,
        ),
        re.compile(
            r"^(transparency|execution\s+risk|operational\s+risk|liquidity\s+risk|margin\s+structure)\s+(in|is|often|matters)\b",
            re.IGNORECASE,
        ),
    ]

    _NARRATIVE_SECTIONS = (
        "Executive Summary",
        "Financial Performance",
        "Management Discussion & Analysis",
        "Closing Takeaway",
    )
    context_terms = _company_specific_terms_from_context(*(context_texts or []))

    def _is_generic(sentence: str) -> bool:
        stripped = sentence.strip()
        for pat in _GENERIC_PATTERNS:
            if pat.search(stripped):
                return True
        return False

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        for section_title in _NARRATIVE_SECTIONS:
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue
            sentences = [
                s.strip()
                for s in re.split(r"(?<=[.!?])\s+", body.strip())
                if s.strip() and len(s.strip().split()) >= 8
            ]
            if not sentences:
                continue
            generic_count = sum(1 for s in sentences if _is_generic(s))
            company_signal_count = 0
            if context_terms:
                for sentence in sentences:
                    sentence_tokens = set(re.findall(r"[a-z]{4,}", sentence.lower()))
                    if sentence_tokens & context_terms:
                        company_signal_count += 1
            if len(sentences) >= 4 and generic_count / len(sentences) > 0.30:
                return (
                    f"Generic filler detected in {section_title}: {generic_count} of {len(sentences)} sentences "
                    "are financial axioms that apply to any company. Replace with company-specific analysis."
                )
            if generic_count >= 5:
                return (
                    f"Excessive generic filler in {section_title}: {generic_count} textbook statements. "
                    "Every sentence should reference this company's specific data or situation."
                )
            if (
                context_terms
                and len(sentences) >= 3
                and generic_count >= 2
                and company_signal_count <= 1
            ):
                return (
                    f"Generic filler detected in {section_title}: the section is dominated by finance abstractions without enough company-specific nouns or filing terms. "
                    "Replace broad balance-sheet or margin commentary with company-specific operating, product, segment, customer, or regulatory analysis."
                )

        return None

    return _validator


def _make_editorial_anchor_validator(
    *,
    company_terms: Optional[List[str]] = None,
    management_expectations: Optional[List[str]] = None,
    promise_scorecard_items: Optional[List[str]] = None,
) -> Callable[[str], Optional[str]]:
    """Require company-specific editorial anchors in the final memo."""

    def _normalize_items(items: Optional[List[str]]) -> List[str]:
        normalized: List[str] = []
        for item in items or []:
            value = " ".join(str(item or "").split()).strip()
            if value:
                normalized.append(value)
        return normalized

    company_phrases = _normalize_items(company_terms)
    expectation_phrases = _normalize_items(management_expectations)
    promise_phrases = _normalize_items(promise_scorecard_items)

    company_term_tokens = _company_specific_terms_from_context(*company_phrases)
    expectation_tokens = _company_specific_terms_from_context(*expectation_phrases)
    promise_tokens = _company_specific_terms_from_context(*promise_phrases)

    forward_re = re.compile(
        r"\b(expect|expects|expected|plan|plans|planned|target|targets|guided|guidance|outlook|next|ahead|pipeline|roadmap)\b",
        re.IGNORECASE,
    )
    status_re = re.compile(
        r"\b(delivered|on track|missed|new commitment|commitment|commitments|credibility|execut(?:ed|ion))\b",
        re.IGNORECASE,
    )

    def _phrase_hits(body: str, phrases: List[str]) -> Set[str]:
        normalized_body = " ".join((body or "").split()).lower()
        hits: Set[str] = set()
        for phrase in phrases:
            if len(phrase.split()) < 2:
                continue
            phrase_norm = phrase.lower()
            if phrase_norm in normalized_body:
                hits.add(phrase_norm)
        return hits

    def _token_hits(body: str, tokens: Set[str]) -> Set[str]:
        body_tokens = set(re.findall(r"[a-z][a-z0-9&.-]{3,}", (body or "").lower()))
        return body_tokens & tokens

    def _combined_hits(body: str, phrases: List[str], tokens: Set[str]) -> Set[str]:
        return _phrase_hits(body, phrases) | _token_hits(body, tokens)

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        for section_title in (
            "Executive Summary",
            "Management Discussion & Analysis",
            "Closing Takeaway",
        ):
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue

            if company_phrases:
                company_hits = _combined_hits(body, company_phrases, company_term_tokens)
                required_hits = 1 if section_title == "Closing Takeaway" else 2
                if len(company_hits) < required_hits:
                    return (
                        f"{section_title} lacks filing-specific company language. "
                        "Use the extracted company/product/segment/program terms instead of generic large-cap commentary."
                    )

            if section_title == "Management Discussion & Analysis":
                if expectation_phrases:
                    expectation_hits = _combined_hits(
                        body, expectation_phrases, expectation_tokens
                    )
                    if not expectation_hits and not forward_re.search(body):
                        return (
                            "Management Discussion & Analysis should use extracted management expectations with timing, "
                            "not generic outlook language."
                        )
                if promise_phrases:
                    promise_hits = _combined_hits(body, promise_phrases, promise_tokens)
                    if not promise_hits and not status_re.search(body):
                        return (
                            "Management Discussion & Analysis should assess promise-vs-delivery using the extracted commitment evidence."
                        )

            if section_title == "Closing Takeaway" and promise_phrases:
                closing_promise_hits = _combined_hits(
                    body, promise_phrases, promise_tokens
                )
                if not closing_promise_hits and not status_re.search(body):
                    return (
                        "Closing Takeaway should tie the stance to management credibility or commitment delivery, "
                        "not just generic balance-sheet or margin commentary."
                    )

        return None

    return _validator


def _make_degraded_specificity_validator(
    *,
    company_terms: Optional[List[str]] = None,
    management_expectations: Optional[List[str]] = None,
    promise_scorecard_items: Optional[List[str]] = None,
) -> Callable[[str], Optional[str]]:
    """Fail drafts that are structurally valid but too weak on company-specific anchors."""

    def _normalize_items(items: Optional[List[str]]) -> List[str]:
        return [
            " ".join(str(item or "").split()).strip()
            for item in (items or [])
            if " ".join(str(item or "").split()).strip()
        ]

    company_phrases = _normalize_items(company_terms)
    expectation_phrases = _normalize_items(management_expectations)
    promise_phrases = _normalize_items(promise_scorecard_items)
    company_tokens = _company_specific_terms_from_context(*company_phrases)
    expectation_tokens = _company_specific_terms_from_context(*expectation_phrases)
    promise_tokens = _company_specific_terms_from_context(*promise_phrases)

    def _combined_hits(body: str, phrases: List[str], tokens: Set[str]) -> Set[str]:
        normalized_body = " ".join((body or "").split()).lower()
        phrase_hits = {
            phrase.lower()
            for phrase in phrases
            if len(phrase.split()) >= 2 and phrase.lower() in normalized_body
        }
        body_tokens = set(re.findall(r"[a-z][a-z0-9&.-]{3,}", normalized_body))
        return phrase_hits | (body_tokens & tokens)

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None
        usable_terms = [
            term
            for term in company_phrases
            if len(_company_specific_terms_from_context(term)) >= 1
        ]
        if usable_terms and len(usable_terms) < 6:
            return (
                "Insufficient company-specific anchors were extracted for this filing. "
                "Fail instead of returning a generic summary."
            )

        for section_title in (
            "Executive Summary",
            "Management Discussion & Analysis",
            "Closing Takeaway",
        ):
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue
            company_hits = _combined_hits(body, company_phrases, company_tokens)
            expectation_hits = _combined_hits(
                body, expectation_phrases, expectation_tokens
            )
            promise_hits = _combined_hits(body, promise_phrases, promise_tokens)
            combined_anchor_hits = company_hits | expectation_hits | promise_hits
            if usable_terms and len(combined_anchor_hits) < 2:
                return (
                    f"{section_title} does not have enough company-specific anchors to be trustworthy. "
                    "Fail instead of shipping generic prose."
                )
        return None

    return _validator


def _make_management_forward_looking_validator(
    *,
    filing_language_snippets: Optional[str],
) -> Callable[[str], Optional[str]]:
    """Require management attribution/quotes and forward-looking implications."""

    has_snippets = bool(" ".join((filing_language_snippets or "").split()).strip())
    quote_re = re.compile(r"[“\"]([^“”\"\n]{8,260})[”\"]")
    attribution_re = re.compile(
        r"\b(management|leadership|the company|executives?|ceo|cfo)\s+"
        r"(?:said|noted|indicated|highlighted|emphasized|acknowledged|cautioned|expects?|plans?|targets?|believes?|described|outlined|guided)\b",
        re.IGNORECASE,
    )
    forward_re = re.compile(
        r"\b(will|would|expect|expects|expected|plan|plans|planned|target|targets|targeted|outlook|guidance|next|ahead|coming|future|pipeline|roadmap|expand|expansion|invest|investment|priority|priorities|remain focused|positioned)\b",
        re.IGNORECASE,
    )

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None
        for section_title in (
            "Executive Summary",
            "Management Discussion & Analysis",
            "Closing Takeaway",
        ):
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue
            if has_snippets and not (
                quote_re.search(body) or attribution_re.search(body)
            ):
                return f"{section_title} should include either a verified direct quote or clear management attribution when filing snippets are available."
            if not forward_re.search(body):
                return f"{section_title} should include at least one forward-looking implication about what management expects, plans, or what happens next."
        return None

    return _validator


def _make_cross_section_question_framing_validator() -> Callable[[str], Optional[str]]:
    """Reject memo drafts that keep re-stating the thesis as a question."""

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        matched_sentences: List[Tuple[str, str]] = []
        for section_title in _SUMMARY_NARRATIVE_REPETITION_SECTIONS:
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue
            sentences = [
                s.strip()
                for s in re.split(r"(?<=[.!?])\s+", body.strip())
                if s.strip() and len(s.strip().split()) >= 8
            ]
            for sentence in sentences:
                if any(
                    pattern.search(sentence)
                    for pattern in _SUMMARY_QUESTION_FRAMING_PATTERNS
                ):
                    matched_sentences.append((section_title, sentence))

        if len(matched_sentences) <= 1:
            return None

        sample_section, sample_sentence = matched_sentences[1]
        sample_sentence = re.sub(r"\s+", " ", sample_sentence).strip()
        return (
            "Question-framing repetition: multiple sections restate the thesis as a question. "
            f"Keep that framing in Executive Summary only and answer it directly elsewhere. Example from {sample_section}: '{sample_sentence[:140]}...'"
        )

    return _validator


def _make_cross_section_theme_repetition_validator(
    *,
    max_sections_per_theme: int = 4,
) -> Callable[[str], Optional[str]]:
    """Detect when the same narrative theme is belabored across too many sections."""

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        theme_section_map: Dict[str, set] = {}
        for section_title in _SUMMARY_NARRATIVE_REPETITION_SECTIONS:
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue
            unquoted_body = _strip_direct_quote_spans(body)
            for theme_name, pattern in _SUMMARY_THEME_PATTERNS.items():
                if pattern.search(unquoted_body):
                    theme_section_map.setdefault(theme_name, set()).add(section_title)

        overused = [
            (theme, sections)
            for theme, sections in theme_section_map.items()
            if len(sections) > int(max_sections_per_theme)
        ]
        if overused:
            worst_theme, worst_sections = max(overused, key=lambda x: len(x[1]))
            return (
                f"Theme over-repetition: '{worst_theme}' discussed in {len(worst_sections)} sections. "
                "Consolidate to the most relevant section and reference briefly elsewhere."
            )
        return None

    return _validator


def _make_period_delta_bridge_validator(
    *, require_bridge: bool
) -> Callable[[str], Optional[str]]:
    def _validator(text: str) -> Optional[str]:
        if not require_bridge:
            return None
        perf_body = _extract_markdown_section_body(text, "Financial Performance")
        if not perf_body:
            return None

        lines = [ln.strip() for ln in perf_body.splitlines() if ln.strip()]
        opening_window = lines[:10]

        # We no longer require a six-line delta bridge. If the section starts with one,
        # force conversion into flowing prose so the memo reads naturally.
        delta_bullets = [
            ln
            for ln in opening_window
            if ln.lstrip().startswith(("-", "•", "·")) and ("Δ" in ln or "→" in ln)
        ]
        if len(delta_bullets) >= 5:
            return (
                "Financial Performance should open with flowing prose (revenue, margins, cash conversion), "
                "not a mandatory delta-bridge checklist. Convert deltas into narrative comparisons."
            )

        normalized = " ".join(perf_body.lower().split())
        has_period_compare = bool(
            re.search(
                r"\b(compared with|compared to|versus|vs\.?|prior quarter|prior year|qoq|yo y|yoy|sequentially|from .* to)\b",
                normalized,
                re.IGNORECASE,
            )
        )
        if not has_period_compare:
            return (
                "Financial Performance is missing an explicit period-over-period comparison. "
                "State what changed versus the prior comparable period and why."
            )

        has_revenue = "revenue" in normalized
        has_margin = "operating margin" in normalized or "net margin" in normalized
        has_cash = (
            "operating cash flow" in normalized
            or "free cash flow" in normalized
            or "cash conversion" in normalized
            or "ocf" in normalized
            or "fcf" in normalized
        )
        if not (has_revenue and has_margin and has_cash):
            return "Financial Performance must cover revenue, margin interpretation, and cash conversion (OCF→FCF) in prose."

        return None

    return _validator


def _make_closing_recommendation_validator(
    *, persona_requested: bool, company_name: str
) -> Callable[[str], Optional[str]]:
    def _validator(text: str) -> Optional[str]:
        closing_body = _extract_markdown_section_body(text, "Closing Takeaway")
        if not closing_body:
            return None
        if not re.search(r"\b(buy|hold|sell)\b", closing_body, re.IGNORECASE):
            voice = "first-person" if persona_requested else "third-person"
            return (
                "Closing Takeaway is missing an explicit Buy/Hold/Sell recommendation. "
                f"Add a clear {voice} recommendation sentence that mentions {company_name}."
            )
        return None

    return _validator


def _make_section_transition_validator(
    *, include_health_rating: bool, target_length: Optional[int] = None
) -> Callable[[str], Optional[str]]:
    """Require conceptual handoffs between major sections for narrative flow."""

    def _tail_blob(body: str) -> str:
        sentences = [
            s.strip()
            for s in re.split(r"(?<=[.!?])\s+", str(body or "").strip())
            if s.strip()
        ]
        if not sentences:
            return ""
        if len(sentences) == 1:
            return sentences[0]
        return " ".join(sentences[-2:])

    transition_rules: List[Tuple[str, str, Tuple[str, ...]]] = [
        (
            "Executive Summary",
            "Financial Performance",
            (
                r"\bfinancial performance\b",
                r"\b(numbers?|results?|evidence|proof|test|operating proof|cash conversion|margin|whether .* holds?)\b",
                r"\bwhat .* must show\b",
            ),
        ),
        (
            "Financial Performance",
            "Management Discussion & Analysis",
            (
                r"\bmanagement discussion(?:\s*&\s*analysis)?|md&a\b",
                r"\b(management|execution|capital allocation|pricing|reinvestment|strategy|sequencing|discipline|decision)\b",
                r"\bwhat management .* next\b",
            ),
        ),
        (
            "Management Discussion & Analysis",
            "Risk Factors",
            (
                r"\brisk factors?\b",
                r"\b(risk|downside|vulnerability|watchpoint|exposure|stress[- ]?test|if .* slips?)\b",
                r"\bwhat could go wrong\b",
            ),
        ),
        (
            "Risk Factors",
            "Key Metrics",
            (
                r"\bkey metrics\b",
                r"\b(metrics?|monitor|watch|indicator|signal|proof point|scoreboard|trigger)\b",
                r"\bearly-warning signal\b",
            ),
        ),
    ]
    if include_health_rating:
        transition_rules.insert(
            0,
            (
                "Financial Health Rating",
                "Executive Summary",
                (
                    r"\b(thesis|backdrop|operating analysis|sets? up|frames?)\b",
                    r"\bexecutive summary\b",
                ),
            ),
        )

    def _validator(text: str) -> Optional[str]:
        for source, target, hints in transition_rules:
            body = _extract_markdown_section_body(text, source)
            if not body:
                continue

            if target_length and target_length <= 350 and _count_words(body) < 35:
                continue

            handoff_window = _tail_blob(body) or body
            if any(
                re.search(hint, handoff_window, re.IGNORECASE)
                or re.search(hint, body, re.IGNORECASE)
                for hint in hints
            ):
                continue

            return (
                f"{source} should end with a conceptual handoff into {target} "
                "so the memo progresses naturally without explicit section-name boilerplate."
            )
        return None

    return _validator


def _make_section_differentiation_validator(
    *,
    company_terms: Optional[List[str]] = None,
    management_expectations: Optional[List[str]] = None,
    promise_scorecard_items: Optional[List[str]] = None,
) -> Callable[[str], Optional[str]]:
    """Detect when narrative sections reuse the same themes instead of progressing."""

    def _normalize_items(items: Optional[List[str]]) -> List[str]:
        normalized: List[str] = []
        for item in items or []:
            value = " ".join(str(item or "").split()).strip()
            if value:
                normalized.append(value)
        return normalized

    company_phrases = _normalize_items(company_terms)
    expectation_phrases = _normalize_items(management_expectations)
    promise_phrases = _normalize_items(promise_scorecard_items)
    company_term_tokens = _company_specific_terms_from_context(*company_phrases)
    expectation_tokens = _company_specific_terms_from_context(*expectation_phrases)
    promise_tokens = _company_specific_terms_from_context(*promise_phrases)

    quote_re = re.compile(r"[“\"]([^“”\"\n]{8,260})[”\"]")
    management_voice_re = re.compile(
        r"\b(management|leadership|executives?|ceo|cfo|the company)\s+"
        r"(?:said|noted|indicated|highlighted|emphasized|acknowledged|cautioned|expects?|plans?|targets?|believes?|described|outlined|guided|prioritized)\b",
        re.IGNORECASE,
    )
    numeric_token_re = re.compile(r"\$[\d,.]+(?:\s*[BMKTbmkt])?|\b\d+(?:\.\d+)?%?\b")
    proof_re = re.compile(
        r"\b(credibility|proof point|proof points|watchpoint|must stay true|breaks the thesis|trigger|changes? the view)\b",
        re.IGNORECASE,
    )
    status_re = re.compile(
        r"\b(delivered|on track|missed|new commitment|commitment|commitments|execution)\b",
        re.IGNORECASE,
    )

    def _combined_hits(body: str, phrases: List[str], tokens: Set[str]) -> Set[str]:
        normalized_body = " ".join((body or "").split()).lower()
        phrase_hits = {
            phrase.lower()
            for phrase in phrases
            if len(phrase.split()) >= 2 and phrase.lower() in normalized_body
        }
        body_tokens = set(re.findall(r"[a-z][a-z0-9&.-]{3,}", normalized_body))
        return phrase_hits | (body_tokens & tokens)

    def _section_theme_keys(body: str) -> Set[str]:
        unquoted = _strip_direct_quote_spans(body or "")
        return {
            theme_name
            for theme_name, pattern in _SUMMARY_THEME_PATTERNS.items()
            if pattern.search(unquoted)
        }

    def _opening_blob(body: str, *, sentence_count: int = 2) -> str:
        sentences = [
            s.strip()
            for s in re.split(r"(?<=[.!?])\s+", str(body or "").strip())
            if s.strip()
        ]
        return " ".join(sentences[:sentence_count])

    def _validator(text: str) -> Optional[str]:
        if not text:
            return None

        exec_body = _extract_markdown_section_body(text, "Executive Summary") or ""
        perf_body = _extract_markdown_section_body(text, "Financial Performance") or ""
        mdna_body = _extract_markdown_section_body(
            text, "Management Discussion & Analysis"
        ) or ""
        closing_body = _extract_markdown_section_body(text, "Closing Takeaway") or ""

        exec_themes = _section_theme_keys(exec_body)
        perf_themes = _section_theme_keys(perf_body)
        mdna_themes = _section_theme_keys(mdna_body)
        closing_themes = _section_theme_keys(closing_body)
        exec_company_hits = _combined_hits(exec_body, company_phrases, company_term_tokens)
        mdna_company_hits = _combined_hits(mdna_body, company_phrases, company_term_tokens)
        closing_company_hits_for_core = _combined_hits(
            closing_body, company_phrases, company_term_tokens
        )

        repeated_core_themes = exec_themes & mdna_themes & closing_themes
        if len(repeated_core_themes) >= 2:
            repeated_list = ", ".join(sorted(repeated_core_themes))
            return (
                "Executive Summary, Management Discussion & Analysis, and Closing Takeaway "
                f"are recycling too many of the same themes ({repeated_list}). "
                "Keep one common thread, but give each section a distinct job."
            )
        generic_core_themes = repeated_core_themes & {
            "cash conversion",
            "reinvestment",
            "margin durability",
            "balance-sheet flexibility",
        }
        if generic_core_themes and min(
            len(exec_company_hits),
            len(mdna_company_hits),
            len(closing_company_hits_for_core),
        ) < 2:
            repeated_list = ", ".join(sorted(generic_core_themes))
            return (
                "Executive Summary, Management Discussion & Analysis, and Closing Takeaway "
                f"are leaning on generic repeated themes ({repeated_list}) without enough distinct company-specific mechanisms. "
                "Keep the thread, but tie each section to different concrete company anchors."
            )

        mdna_opening = _opening_blob(mdna_body, sentence_count=2)
        if mdna_opening:
            numeric_hits = numeric_token_re.findall(mdna_opening)
            if len(numeric_hits) >= 2 and not (
                quote_re.search(mdna_opening) or management_voice_re.search(mdna_opening)
            ):
                return (
                    "Management Discussion & Analysis opens like a performance recap. "
                    "Lead with management voice, attribution, priorities, or guidance before numbers."
                )

        perf_mdna_overlap = perf_themes & mdna_themes
        mdna_expectation_hits = _combined_hits(
            mdna_body, expectation_phrases, expectation_tokens
        )
        mdna_promise_hits = _combined_hits(mdna_body, promise_phrases, promise_tokens)
        if len(perf_mdna_overlap) >= 2 and not (
            mdna_expectation_hits
            or mdna_promise_hits
            or quote_re.search(mdna_body)
            or management_voice_re.search(mdna_body)
        ):
            repeated_list = ", ".join(sorted(perf_mdna_overlap))
            return (
                "Management Discussion & Analysis is replaying Financial Performance "
                f"themes ({repeated_list}) instead of shifting to management mechanism, intent, and credibility."
            )

        closing_overlap = perf_themes & closing_themes
        closing_expectation_hits = _combined_hits(
            closing_body, expectation_phrases, expectation_tokens
        )
        closing_promise_hits = _combined_hits(
            closing_body, promise_phrases, promise_tokens
        )
        closing_company_hits = _combined_hits(
            closing_body, company_phrases, company_term_tokens
        )
        if len(closing_overlap) >= 2 and not (
            proof_re.search(closing_body)
            or status_re.search(closing_body)
            or closing_expectation_hits
            or closing_promise_hits
            or len(closing_company_hits) >= 1
        ):
            repeated_list = ", ".join(sorted(closing_overlap))
            return (
                "Closing Takeaway is replaying Financial Performance "
                f"themes ({repeated_list}) instead of judging management credibility and the next proof points."
            )

        return None

    return _validator


def _make_closing_structure_validator() -> Callable[[str], Optional[str]]:
    """Enforce a decisive closing with one stance and measurable trigger(s)."""

    stance_re = re.compile(r"\b(buy|hold|sell|neutral)\b", re.IGNORECASE)
    time_window_re = re.compile(
        r"\b(?:over|for|in)\s+the\s+next\s+[a-z0-9\-\s]+?\b(?=[,.;]|$)",
        re.IGNORECASE,
    )
    measurable_re = re.compile(
        r"(\$?\d+(?:\.\d+)?\s*(?:%|x|pp|b|m|bn|mm)?|\babove\b|\bbelow\b|\bat least\b|\bless than\b|\bmore than\b)",
        re.IGNORECASE,
    )
    timeframe_re = re.compile(
        r"\b(next|quarter|quarters|month|months|year|years|period|periods|q[1-4]|fy\d{2})\b",
        re.IGNORECASE,
    )
    upgrade_re = re.compile(
        r"\b(upgrade|upside|more constructive|buy)\b", re.IGNORECASE
    )
    downgrade_re = re.compile(
        r"\b(downgrade|downside|more defensive|sell)\b", re.IGNORECASE
    )
    must_hold_re = re.compile(
        r"\b(while|so long as|as long as|holds?|remains?|stays?|upgrade|upside|buy)\b",
        re.IGNORECASE,
    )
    break_re = re.compile(
        r"\b(breaks?|falls?|below|compress(?:es|ion)?|deteriorat(?:e|es|ion)|weakens?|downgrade|sell|downside)\b",
        re.IGNORECASE,
    )
    parenthetical_filler_re = re.compile(
        r"\((?:on a forward basis|from a portfolio perspective|as things stand|in this environment|at this stage)\)",
        re.IGNORECASE,
    )
    legacy_parenthetical_filler_re = re.compile(
        r"\((?:key swing factor|primary swing factor|near term factors|in practical terms|fundamental catalyst|structural driver|"
        r"operating backdrop|valuation context|execution priority|capital intensity backdrop|on a forward basis|relative to the cycle|"
        r"across the enterprise|from a risk standpoint|on a relative basis|under current conditions|given the trajectory|within this framework)\)",
        re.IGNORECASE,
    )

    def _validator(text: str) -> Optional[str]:
        closing_body = _extract_markdown_section_body(text, "Closing Takeaway")
        if not closing_body:
            return None

        if parenthetical_filler_re.search(
            closing_body
        ) or legacy_parenthetical_filler_re.search(closing_body):
            return (
                "Closing Takeaway contains parenthetical buzzword filler. "
                "Remove parenthetical buzzwords and keep direct investor prose."
            )
        parenthetical_chunks = re.findall(r"\(([^)\n]{1,60})\)", closing_body)
        # Hard cap: more than 3 parenthetical fragments total is always a smell
        if len(parenthetical_chunks) > 3:
            return (
                "Closing Takeaway has too many parenthetical asides "
                f"({len(parenthetical_chunks)} found). Remove them and write clean prose."
            )
        low_signal_parentheticals = 0
        for chunk in parenthetical_chunks:
            chunk_norm = " ".join((chunk or "").lower().split())
            if not chunk_norm:
                continue
            if re.search(
                r"\d|%|\$|buy|hold|sell|if|unless|q[1-4]|fy\d{2}",
                chunk_norm,
                re.IGNORECASE,
            ):
                continue
            if len(chunk_norm.split()) <= 5:
                low_signal_parentheticals += 1
        if low_signal_parentheticals >= 2:
            return (
                "Closing Takeaway contains low-signal parenthetical fragments. "
                "Rewrite as clean prose without parenthetical filler."
            )

        sentences = [
            s.strip()
            for s in re.split(r"(?<=[.!?])\s+", closing_body.strip())
            if s.strip()
        ]
        closing_shape = get_closing_takeaway_shape(_count_words(closing_body))
        max_allowed_sentences = max(6, int(closing_shape.max_sentences))
        if len(sentences) > max_allowed_sentences:
            return (
                f"Closing Takeaway has {len(sentences)} sentences. "
                f"Use at most {max_allowed_sentences} sentences and preserve the verdict / must-stay-true / breaks-thesis structure."
            )

        trigger_sentences: List[Tuple[int, str]] = []
        for idx, sentence in enumerate(sentences):
            lowered = sentence.lower()
            if not re.search(r"\b(if|unless|would|trigger|flip|change)\b", lowered):
                continue
            if not measurable_re.search(sentence):
                continue
            if not timeframe_re.search(sentence):
                continue
            trigger_sentences.append((idx, sentence))

        trigger_indexes = {idx for idx, _ in trigger_sentences}
        stance_tokens: List[str] = []
        for idx, sentence in enumerate(sentences):
            if idx in trigger_indexes:
                continue
            for match in stance_re.finditer(sentence):
                token = (match.group(1) or "").lower()
                if token:
                    stance_tokens.append(token)

        normalized_stances = {
            "hold" if token == "neutral" else token for token in stance_tokens
        }
        if len(normalized_stances) == 0:
            return (
                "Closing Takeaway must state exactly one explicit stance (BUY, HOLD, or SELL). "
                "Add one clear recommendation sentence."
            )
        if len(normalized_stances) > 1:
            labels = ", ".join(sorted(token.upper() for token in normalized_stances))
            return (
                f"Closing Takeaway contains conflicting stances ({labels}). "
                "Use exactly one explicit recommendation."
            )

        trigger_sentence_text = [sentence for _idx, sentence in trigger_sentences]
        if len(trigger_sentence_text) < 1:
            return (
                "Closing Takeaway must include at least one measurable monitoring trigger "
                "that clearly states what would change the view."
            )

        has_must_hold = any(must_hold_re.search(s) for s in trigger_sentence_text)
        if not has_must_hold:
            return (
                "Closing Takeaway is missing the 'what must stay true' condition. "
                "Add one measurable trigger describing what needs to hold to keep the thesis intact."
            )

        has_break = any(break_re.search(s) for s in trigger_sentence_text)
        if not has_break:
            return (
                "Closing Takeaway is missing the 'what breaks the thesis' condition. "
                "Add one measurable downside trigger with a clear threshold and timeframe."
            )

        has_directional_trigger = any(
            upgrade_re.search(s) or downgrade_re.search(s)
            for s in trigger_sentence_text
        )
        if not has_directional_trigger:
            return (
                "Closing Takeaway trigger(s) must be directional (upgrade or downgrade) "
                "and measurable over a timeframe."
            )

        window_phrases = []
        for sentence in trigger_sentence_text:
            match = time_window_re.search(sentence)
            if match:
                window_phrases.append(" ".join(match.group(0).lower().split()))
        if len(window_phrases) >= 2 and len(set(window_phrases)) == 1:
            return (
                "Closing Takeaway repeats the same monitoring-window phrase across triggers. "
                "Use distinct windows to improve decisiveness."
            )

        return None

    return _validator


def _make_stance_consistency_validator() -> Callable[[str], Optional[str]]:
    """Ensure the memo uses a single Buy/Hold/Sell stance consistently.

    Catches two problems:
    1. Intra-section oscillation — the Closing Takeaway itself contains
       multiple conflicting stance words (e.g. "neutral" + "buy" + "hold").
    2. Cross-section inconsistency — other sections contradict the Closing
       Takeaway's stance.
    """

    _stance_re = re.compile(r"\b(buy|hold|sell|neutral)\b", re.IGNORECASE)

    def _last_stance(text: str) -> Optional[str]:
        matches = list(re.finditer(r"\b(buy|hold|sell)\b", text or "", re.IGNORECASE))
        if not matches:
            return None
        return (matches[-1].group(1) or "").strip().lower() or None

    def _validator(text: str) -> Optional[str]:
        closing_body = _extract_markdown_section_body(text, "Closing Takeaway")
        if not closing_body:
            return None

        # --- Check 1: intra-Closing-Takeaway stance oscillation ---
        stance_matches = list(_stance_re.finditer(closing_body))
        if stance_matches:
            distinct_stances = {m.group(1).lower() for m in stance_matches}
            # "neutral" and "hold" are close enough — treat as equivalent
            normalized = set()
            for s in distinct_stances:
                normalized.add("hold" if s == "neutral" else s)
            if len(normalized) > 1:
                labels = ", ".join(sorted(s.upper() for s in distinct_stances))
                return (
                    f"Closing Takeaway contains conflicting stances ({labels}). "
                    "The section must commit to ONE clear recommendation — pick a single stance "
                    "and remove all contradictory stance words."
                )

        closing_stance = _last_stance(closing_body)
        if not closing_stance:
            return None

        # --- Check 2: cross-section consistency ---
        # Scan all non-closing sections for stance words; they must either be absent
        # or match the Closing Takeaway stance.
        pattern = re.compile(r"^\s*##\s*(.+)\s*$", re.MULTILINE)
        matches = list(pattern.finditer(text or ""))
        for idx, match in enumerate(matches):
            heading_title = (match.group(1) or "").strip()
            heading_line = f"## {heading_title}".strip()
            start = match.end()
            end = matches[idx + 1].start() if idx + 1 < len(matches) else len(text)
            body = (text or "")[start:end].strip()

            canon = _standard_section_name_from_heading(heading_line)
            if canon == "Closing Takeaway":
                continue

            other_stance = _last_stance(body or "")
            if other_stance and other_stance != closing_stance:
                return (
                    f"Recommendation stance is inconsistent: Closing Takeaway is '{closing_stance.upper()}', "
                    f"but '{canon}' contains '{other_stance.upper()}'. Use ONE stance consistently."
                )
        return None

    return _validator


def _first_quality_validator_issue(
    text: str, validators: Optional[List[Callable[[str], Optional[str]]]]
) -> Tuple[Optional[str], Optional[str]]:
    if not validators:
        return None, None
    for validator in validators:
        issue = validator(text)
        if not issue:
            continue
        validator_name = getattr(validator, "__name__", None) or getattr(
            validator, "__qualname__", repr(validator)
        )
        return issue, str(validator_name)
    return None, None


def _build_post_final_quality_validators(
    *,
    include_health_rating: bool,
    target_length: Optional[int],
    profile: SummaryFlowQualityProfile,
    v2_enabled: bool,
    persona_requested: bool,
    company_name: str,
    explicit_target_requested: bool = False,
    source_text: Optional[str] = None,
    filing_language_snippets: Optional[str] = None,
    risk_factors_excerpt: Optional[str] = None,
    require_quotes: bool = False,
) -> List[Callable[[str], Optional[str]]]:
    quote_policy = _summary_quote_policy_for_target_length(target_length)
    validators: List[Callable[[str], Optional[str]]] = [
        _make_section_transition_validator(
            include_health_rating=include_health_rating, target_length=target_length
        ),
        _make_sentence_stem_repetition_validator(
            max_same_opening=profile.max_same_opening
        ),
        _make_cross_section_question_framing_validator(),
        _make_cross_section_number_repetition_validator(
            max_sections_per_figure=profile.max_sections_per_repeated_number
        ),
        _make_cross_section_theme_repetition_validator(
            max_sections_per_theme=profile.max_sections_per_theme
        ),
        _make_numbers_discipline_validator(
            target_length,
            closing_numeric_cap_override=profile.closing_numeric_anchor_cap,
        ),
        _make_closing_recommendation_validator(
            persona_requested=persona_requested,
            company_name=company_name,
        ),
        _make_closing_structure_validator(),
        _make_management_forward_looking_validator(
            filing_language_snippets=filing_language_snippets
        ),
    ]
    if _is_short_quality_sensitive_target(target_length):
        validators.insert(1, _make_verbatim_repetition_validator())
        validators.insert(2, _make_phrase_limits_validator())
        validators.insert(3, _make_instruction_leak_validator())
        validators.insert(
            7,
            _make_generic_filler_validator(
                context_texts=[
                    source_text or "",
                    filing_language_snippets or "",
                    risk_factors_excerpt or "",
                ]
            ),
        )
    if source_text:
        validators.append(
            _make_quote_grounding_validator(
                source_text=source_text,
                require_quotes=require_quotes,
                min_required_quotes=quote_policy["min_quotes"],
                max_allowed_quotes=quote_policy["max_quotes"],
            )
        )
    if _requires_section_balance_contract(
        target_length=target_length,
        explicit_target_requested=explicit_target_requested,
        v2_enabled=v2_enabled,
    ):
        validators.append(
            _make_section_balance_validator(
                include_health_rating=include_health_rating,
                target_length=int(target_length),
            )
        )
    if risk_factors_excerpt:
        validators.append(
            _make_risk_specificity_validator(
                risk_factors_excerpt=risk_factors_excerpt
            )
        )
    return validators


def _build_pipeline_editorial_validators(
    pipeline_result: Optional[PipelineResult],
) -> List[Callable[[str], Optional[str]]]:
    analysis = getattr(pipeline_result, "filing_analysis", None)
    if analysis is None:
        return []

    company_terms = [
        str(term).strip()
        for term in list(getattr(analysis, "company_terms", []) or [])
        if str(term or "").strip()
    ]
    expectation_lines = [
        " ".join(
            part
            for part in (
                str(getattr(item, "topic", "") or "").strip(),
                str(getattr(item, "expectation", "") or "").strip(),
                str(getattr(item, "timeframe", "") or "").strip(),
                str(getattr(item, "evidence", "") or "").strip(),
            )
            if part
        ).strip()
        for item in list(getattr(analysis, "management_expectations", []) or [])
    ]
    expectation_lines = [item for item in expectation_lines if item]
    promise_lines = [
        " ".join(
            part
            for part in (
                str(getattr(item, "commitment", "") or "").strip(),
                str(getattr(item, "status", "") or "").strip(),
                str(getattr(item, "assessment", "") or "").strip(),
                str(getattr(item, "evidence", "") or "").strip(),
            )
            if part
        ).strip()
        for item in list(getattr(analysis, "promise_scorecard_items", []) or [])
    ]
    promise_lines = [item for item in promise_lines if item]

    if not (company_terms or expectation_lines or promise_lines):
        return []

    return [
        _make_editorial_anchor_validator(
            company_terms=company_terms,
            management_expectations=expectation_lines,
            promise_scorecard_items=promise_lines,
        ),
        _make_degraded_specificity_validator(
            company_terms=company_terms,
            management_expectations=expectation_lines,
            promise_scorecard_items=promise_lines,
        ),
        _make_section_differentiation_validator(
            company_terms=company_terms,
            management_expectations=expectation_lines,
            promise_scorecard_items=promise_lines,
        ),
    ]


def _make_pipeline_section_regenerator(
    *,
    pipeline_result: Optional[PipelineResult],
    company_name: str,
    target_length: Optional[int],
    financial_snapshot: str,
    metrics_lines: str,
    health_score_data: Optional[Dict[str, Any]],
    openai_client: Any,
) -> Optional[Callable[..., str]]:
    if pipeline_result is None:
        return None
    required_attrs = ("company_intelligence", "filing_analysis")
    if any(
        getattr(pipeline_result, attr, None) is None for attr in required_attrs
    ):
        return None

    def _regenerate(
        *,
        section_name: str,
        budget: int,
        failure_reason: str,
        prior_section_text: str,
        existing_section_text: str,
        used_claims: List[str],
        section_memory: Optional[Dict[str, Any]] = None,
    ) -> str:
        return regenerate_pipeline_section_body(
            pipeline_result=pipeline_result,
            section_name=section_name,
            company_name=company_name,
            target_length=target_length,
            financial_snapshot=financial_snapshot,
            metrics_lines=metrics_lines,
            health_score_data=health_score_data,
            budget=budget,
            prior_section_text=prior_section_text,
            used_claims=used_claims,
            section_memory=section_memory,
            openai_client=openai_client,
            failure_reason=failure_reason,
            section_instructions=(
                pipeline_result.metadata.get("section_instructions")
                if getattr(pipeline_result, "metadata", None)
                else None
            ),
        )

    return _regenerate


def _count_direct_quotes_in_section(summary_text: str, section_title: str) -> int:
    body = _extract_markdown_section_body(summary_text, section_title) or ""
    if not body:
        return 0
    return len(re.findall(r"[“\"]([^“”\"\n]{8,260})[”\"]", body))


def _apply_short_form_structural_seal(
    summary_text: str,
    *,
    include_health_rating: bool,
    metrics_lines: str,
    calculated_metrics: Dict[str, Any],
    company_name: str,
    risk_factors_excerpt: Optional[str] = None,
    health_score_data: Optional[Dict[str, Any]] = None,
    health_rating_config: Optional[Dict[str, Any]] = None,
    persona_name: Optional[str] = None,
    persona_requested: bool = False,
    target_length: Optional[int] = None,
    preserve_pipeline_editorial: bool = False,
) -> str:
    text = (summary_text or "").strip()
    if not text:
        return summary_text

    text = _merge_duplicate_canonical_sections(
        text, include_health_rating=include_health_rating
    )
    text = _ensure_required_sections(
        text,
        include_health_rating=include_health_rating,
        metrics_lines=metrics_lines,
        calculated_metrics=calculated_metrics,
        health_score_data=health_score_data,
        company_name=company_name,
        risk_factors_excerpt=risk_factors_excerpt,
        health_rating_config=health_rating_config,
        persona_name=persona_name,
        persona_requested=persona_requested,
        target_length=target_length,
    )
    if (metrics_lines or "").strip():
        text = _canonicalize_key_metrics_section(text, metrics_lines)
    text = _inject_data_grid_markers_if_missing(text)
    if not preserve_pipeline_editorial:
        text = _ensure_section_transition_handoffs(
            text,
            include_health_rating=include_health_rating,
            target_length=target_length,
        )
    risk_body = _extract_markdown_section_body(text, "Risk Factors") or ""
    if risk_body.strip() and target_length and not preserve_pipeline_editorial:
        risk_issue = _make_risk_specificity_validator(
            risk_factors_excerpt=risk_factors_excerpt
        )(text)
        if risk_issue:
            risk_budget_words = int(
                _calculate_section_word_budgets(
                    int(target_length),
                    include_health_rating=include_health_rating,
                ).get("Risk Factors", 0)
                or 0
            )
            if risk_budget_words > 0:
                normalized_risk_body, risk_info = _normalize_risk_factors_section_body(
                    risk_body,
                    risk_budget_words=risk_budget_words,
                    risk_factors_excerpt=risk_factors_excerpt or "",
                    calculated_metrics=calculated_metrics,
                    health_score_data=health_score_data,
                    rewrite_risk_name_fn=lambda name: _rewrite_generic_risk_name_for_repair(
                        name,
                        risk_factors_excerpt=risk_factors_excerpt or "",
                    ),
                    synthesize_risk_factors_addendum_fn=(
                        _synthesize_risk_factors_addendum
                        if "_synthesize_risk_factors_addendum" in globals()
                        else None
                    ),
                )
                if risk_info.get("applied") and normalized_risk_body:
                    text = _replace_markdown_section_body(
                        text,
                        "Risk Factors",
                        normalized_risk_body,
                    )
    if not preserve_pipeline_editorial:
        text = _cleanup_sentence_artifacts(text)
        text = _validate_complete_sentences(text)
        text = _dedupe_consecutive_sentences(text)
        text = _dedupe_repeated_paragraphs(text)
        text = _repair_closing_recommendation_in_summary(
            text,
            company_name=company_name,
            calculated_metrics=calculated_metrics,
            persona_requested=bool(persona_requested or persona_name),
        )
    text = _merge_duplicate_canonical_sections(
        text, include_health_rating=include_health_rating
    )
    return text


def _is_blocking_quality_validator_issue(issue: str) -> bool:
    normalized = " ".join(str(issue or "").split()).strip().lower()
    if not normalized:
        return False

    flags = _parse_summary_contract_missing_requirements([str(issue)])
    if (
        flags.get("bridge_issue")
        or flags.get("closing_trigger_issue")
        or flags.get("numbers_discipline_issue")
        or flags.get("quote_distribution_issue")
        or flags.get("quote_grounding_issue")
        or flags.get("management_voice_issue")
    ):
        return True

    blocking_snippets = (
        "recycling too many of the same themes",
        "leaning on generic repeated themes",
        "is replaying financial performance themes",
        "lacks filing-specific company language",
        "does not have enough company-specific anchors",
        "should use extracted management expectations",
        "should assess promise-vs-delivery",
        "should tie the stance to management credibility",
        "should include at least one forward-looking implication",
        "should include either a verified direct quote or clear management attribution",
    )
    if any(snippet in normalized for snippet in blocking_snippets):
        return True

    if normalized.startswith("closing takeaway") and any(
        snippet in normalized
        for snippet in (
            "must state exactly one explicit stance",
            "must include at least one measurable monitoring trigger",
            "is missing the 'what must stay true' condition",
            "is missing the 'what breaks the thesis' condition",
            "contains conflicting stances",
            "contains parenthetical buzzword filler",
            "has too many parenthetical asides",
            "contains low-signal parenthetical fragments",
        )
    ):
        return True

    return False


def _evaluate_summary_contract_requirements(
    *,
    summary_text: str,
    target_length: Optional[int],
    include_health_rating: bool,
    quality_validators: Optional[List[Callable[[str], Optional[str]]]],
    source_text: Optional[str],
    filing_language_snippets: str,
    enforce_quote_contract: bool,
) -> Tuple[List[str], Dict[str, Any]]:
    text = (summary_text or "").strip()
    missing_requirements: List[str] = []
    quality_checks_passed: List[str] = []
    quality_issues: List[str] = []
    micro_plaintext_mode = _is_micro_plaintext_target(target_length)

    final_word_count = _count_words(text)
    final_split_count = len(text.split())
    if target_length:
        target = int(target_length)
        tol = _effective_word_band_tolerance(target_length)
        lower = max(TARGET_LENGTH_MIN_WORDS, target - tol)
        upper = min(TARGET_LENGTH_MAX_WORDS, target + tol)
        # Use the canonical stripped count as the single source of truth.
        # The split count is tracked for diagnostics but does NOT gate the
        # contract — punctuation-heavy financial text (→, $, %, —) creates a
        # natural 15-30 word divergence between split() and _count_words(),
        # making a dual-counter AND gate effectively impossible to satisfy.
        if not (lower <= final_word_count <= upper):
            missing_requirements.append(
                f"Final word-count band violation: expected {lower}-{upper}, got split={final_split_count}, stripped={final_word_count}."
            )

    if not micro_plaintext_mode:
        # Always run section-completeness for sectioned memo outputs.
        completeness_issue = _make_section_completeness_validator(
            include_health_rating=include_health_rating, target_length=target_length
        )(text)
        if completeness_issue:
            missing_requirements.append(completeness_issue)

    for validator in quality_validators or []:
        validator_name = getattr(validator, "__name__", None) or getattr(
            validator, "__qualname__", repr(validator)
        )
        issue = validator(text)
        if issue:
            normalized_issue = " ".join(str(issue or "").split()).strip().lower()
            if (
                "risk_specificity" in str(validator_name or "").lower()
                or _is_risk_specificity_requirement(normalized_issue)
                or _is_blocking_quality_validator_issue(str(issue))
            ):
                missing_requirements.append(str(issue))
            else:
                quality_issues.append(f"{validator_name}: {issue}")
        else:
            quality_checks_passed.append(str(validator_name))

    exec_quotes = 0
    mdna_quotes = 0
    quote_count_total = 0
    key_metrics_numeric_rows = 0
    if not micro_plaintext_mode:
        exec_quotes = _count_direct_quotes_in_section(text, "Executive Summary")
        mdna_quotes = _count_direct_quotes_in_section(
            text, "Management Discussion & Analysis"
        )
        quote_count_total = exec_quotes + mdna_quotes

        key_metrics_body = _extract_markdown_section_body(text, "Key Metrics") or ""
        key_metrics_issue, key_metrics_numeric_rows = (
            _validate_key_metrics_numeric_block(
                key_metrics_body,
                min_rows=5,
                require_markers=True,
            )
        )
        # Fallback: accept valid numeric rows even without DATA_GRID markers.
        if key_metrics_issue and "Missing DATA_GRID" in str(key_metrics_issue):
            key_metrics_issue, key_metrics_numeric_rows = (
                _validate_key_metrics_numeric_block(
                    key_metrics_body,
                    min_rows=5,
                    require_markers=False,
                )
        )
        if key_metrics_issue:
            missing_requirements.append(key_metrics_issue)

        if enforce_quote_contract:
            if not (filing_language_snippets or "").strip():
                missing_requirements.append(
                    "Insufficient filing-language evidence for quote contract. Re-ingest filing text with richer narrative context."
                )
            else:
                quote_policy = _summary_quote_policy_for_target_length(target_length)
                quote_issue = _make_quote_grounding_validator(
                    source_text=source_text,
                    require_quotes=True,
                    min_required_quotes=quote_policy["min_quotes"],
                    max_allowed_quotes=quote_policy["max_quotes"],
                )(text)
                if quote_issue:
                    missing_requirements.append(quote_issue)
                if quote_policy["exec_min"] >= 1 and exec_quotes < 1:
                    missing_requirements.append(
                        "Executive Summary must include at least one verified direct quote."
                    )
                if quote_policy["mdna_min"] >= 1 and mdna_quotes < 1:
                    missing_requirements.append(
                        "Management Discussion & Analysis must include at least one verified direct quote."
                    )

    # Remaining quality issues are preserved in meta["quality_issues"] for
    # diagnostics only. Blocking editorial failures are promoted into
    # missing_requirements above so they cannot silently ship.

    # De-duplicate while preserving order.
    deduped_missing: List[str] = []
    seen_missing: Set[str] = set()
    for item in missing_requirements:
        key = " ".join((item or "").split()).strip().lower()
        if not key or key in seen_missing:
            continue
        seen_missing.add(key)
        deduped_missing.append(item)

    meta: Dict[str, Any] = {
        "target_length": int(target_length) if target_length else None,
        "final_word_count": final_word_count,
        "final_split_word_count": final_split_count,
        "verified_quote_count": quote_count_total,
        "key_metrics_numeric_row_count": int(key_metrics_numeric_rows),
        "quality_checks_passed": quality_checks_passed,
        "quality_issues": quality_issues,
    }
    return deduped_missing, meta


def _collect_section_body_word_counts(
    summary_text: str, *, include_health_rating: bool
) -> Dict[str, int]:
    counts: Dict[str, int] = {}
    titles = [
        "Financial Health Rating",
        "Executive Summary",
        "Financial Performance",
        "Management Discussion & Analysis",
        "Risk Factors",
        "Key Metrics",
        "Closing Takeaway",
    ]
    if not include_health_rating:
        titles = [title for title in titles if title != "Financial Health Rating"]
    for title in titles:
        body = _extract_markdown_section_body(summary_text or "", title) or ""
        counts[title] = _count_words(body)
    return counts


def _short_underweight_section_guidance(
    summary_text: str,
    *,
    target_length: int,
    include_health_rating: bool,
) -> Tuple[List[str], str]:
    """Describe the most underweight narrative sections for short-form rescue rewrites."""
    budgets = _calculate_section_word_budgets(
        target_length, include_health_rating=include_health_rating
    )
    counts = _collect_section_body_word_counts(
        summary_text, include_health_rating=include_health_rating
    )
    narrative_titles = [
        "Financial Health Rating",
        "Executive Summary",
        "Financial Performance",
        "Management Discussion & Analysis",
        "Risk Factors",
        "Closing Takeaway",
    ]
    if not include_health_rating:
        narrative_titles = [
            title for title in narrative_titles if title != "Financial Health Rating"
        ]

    underweight_rows: List[Tuple[int, int, int, str]] = []
    priority = {
        "Financial Performance": 0,
        "Management Discussion & Analysis": 1,
        "Risk Factors": 2,
        "Executive Summary": 3,
        "Financial Health Rating": 4,
        "Closing Takeaway": 5,
    }
    for title in narrative_titles:
        budget = int(budgets.get(title, 0) or 0)
        observed = int(counts.get(title, 0) or 0)
        if budget <= 0:
            continue
        deficit = budget - observed
        if deficit <= 0:
            continue
        underweight_rows.append((deficit, observed, budget, title))

    if not underweight_rows:
        return [], ""

    underweight_rows.sort(
        key=lambda item: (int(priority.get(item[3], 999)), -int(item[0]))
    )
    ordered_titles = [title for _deficit, _observed, _budget, title in underweight_rows]
    guidance_lines = [
        (
            f"{title}: currently {observed} words versus a {budget}-word budget "
            f"(expand by about {deficit} words)."
        )
        for deficit, observed, budget, title in underweight_rows[:4]
    ]
    return ordered_titles, "\n".join(guidance_lines)


def _rescue_short_sectioned_underflow(
    summary_text: str,
    *,
    target_length: int,
    include_health_rating: bool,
    calculated_metrics: Dict[str, Any],
    company_name: str,
    gemini_client: Optional[Any],
    quality_validators: Optional[List[Callable[[str], Optional[str]]]],
    generation_stats: Optional[Dict[str, Any]] = None,
    strict_contract_required: bool = False,
    token_budget: Optional[TokenBudget] = None,
    cost_budget: Optional[SummaryCostBudget] = None,
    max_output_tokens: int = DEFAULT_OPENAI_MAX_OUTPUT_TOKENS,
    persona_intensity: str = "strong",
) -> str:
    """Run one short-form, section-aware rewrite when cleanup leaves the memo under target."""
    if not summary_text or not _is_short_mid_precision_target(target_length):
        return summary_text
    if gemini_client is None:
        return summary_text

    target = int(target_length)
    band = _target_word_band_bounds(target)
    if band is None:
        return summary_text
    lower, upper, tolerance = band
    split_wc = len((summary_text or "").split())
    stripped_wc = _count_words(summary_text or "")
    if split_wc >= lower and stripped_wc >= lower:
        return summary_text
    if split_wc > upper or stripped_wc > upper:
        return summary_text

    underweight_titles, guidance_block = _short_underweight_section_guidance(
        summary_text,
        target_length=target,
        include_health_rating=include_health_rating,
    )
    section_focus = (
        ", ".join(underweight_titles[:4]) or "the shortest narrative sections"
    )
    quality_hint = (
        f"Short-form underflow rescue: the memo is {max(lower - split_wc, lower - stripped_wc, 0)} words short of the "
        f"required {target} ±{tolerance} band. Expand filing-grounded causal analysis in these underweight sections first: "
        f"{section_focus}. Preserve all headings, quotes, numeric facts, DATA_GRID/Key Metrics rows, and the final stance. "
        "Do not add filler, process narration, or repeated framework sentences."
    )
    if guidance_block:
        quality_hint += f"\nSection budget gaps:\n{guidance_block}"

    if generation_stats is not None:
        generation_stats["short_underflow_rescue_used"] = True
        generation_stats["short_underflow_rescue_initial_split_words"] = int(split_wc)
        generation_stats["short_underflow_rescue_initial_stripped_words"] = int(
            stripped_wc
        )
        generation_stats["short_underflow_rescue_targets"] = list(
            underweight_titles[:4]
        )

    pre_rebalance_flags: Dict[str, Any] = {
        "section_balance_issue": True,
        "section_balance_underweight_titles": list(underweight_titles[:4]),
    }
    summary_text, pre_rebalance_info = _rebalance_section_budgets_deterministically(
        summary_text,
        target_length=target,
        include_health_rating=include_health_rating,
        section_balance_contract_required=True,
        issue_flags=pre_rebalance_flags,
        generation_stats=generation_stats,
        calculated_metrics=calculated_metrics,
    )
    if generation_stats is not None:
        generation_stats["short_underflow_rescue_pre_rebalance_applied"] = bool(
            pre_rebalance_info.get("applied")
        )
        generation_stats["short_underflow_rescue_pre_rebalance_words_added"] = int(
            pre_rebalance_info.get("words_added", 0) or 0
        )
        generation_stats["short_underflow_rescue_pre_rebalance_words_trimmed"] = int(
            pre_rebalance_info.get("words_trimmed", 0) or 0
        )
        generation_stats["short_underflow_rescue_pre_rebalance_expanded_sections"] = (
            list(pre_rebalance_info.get("expanded_sections") or [])
        )

    split_wc = len((summary_text or "").split())
    stripped_wc = _count_words(summary_text or "")
    force_compact_rewrite = bool(target <= 500 and underweight_titles)
    if split_wc >= lower and stripped_wc >= lower and not force_compact_rewrite:
        if generation_stats is not None:
            generation_stats["short_underflow_rescue_in_band"] = bool(
                lower <= split_wc <= upper and lower <= stripped_wc <= upper
            )
            generation_stats["short_underflow_rescue_final_split_words"] = int(split_wc)
            generation_stats["short_underflow_rescue_final_stripped_words"] = int(
                stripped_wc
            )
        return summary_text

    emergency_rewrite_stats: Optional[Dict[str, Any]] = generation_stats
    if generation_stats is not None:
        rewrite_calls = int(generation_stats.get("rewrite_call_count", 0) or 0)
        if rewrite_calls >= int(MAX_REWRITE_ATTEMPTS):
            emergency_rewrite_stats = None

    rewritten_text, _ = _rewrite_summary_to_length(
        gemini_client,
        summary_text,
        target,
        quality_validators,
        current_words=max(split_wc, stripped_wc),
        token_budget=token_budget,
        cost_budget=cost_budget,
        max_output_tokens=max_output_tokens,
        generation_stats=emergency_rewrite_stats,
        persona_intensity=persona_intensity,
        quality_issue_hint=quality_hint,
        allow_over_target_recovery=True,
        ignore_max_rewrite_attempts=True,
        timeout_seconds=_summary_rewrite_timeout_seconds(),
    )
    if not rewritten_text or not rewritten_text.strip():
        return summary_text

    if emergency_rewrite_stats is None and generation_stats is not None:
        generation_stats["short_underflow_reserved_rewrite_used"] = True

    summary_text = _run_summary_cleanup_pass(
        rewritten_text,
        include_health_rating=include_health_rating,
        calculated_metrics=calculated_metrics,
        company_name=company_name,
    )
    if strict_contract_required:
        summary_text = _apply_contract_structural_repairs(
            summary_text,
            include_health_rating=include_health_rating,
            target_length=target_length,
            calculated_metrics=calculated_metrics,
        )
    summary_text = _remove_metric_echo_loops(summary_text)
    summary_text = _merge_staccato_paragraphs(summary_text)
    summary_text = _cap_closing_sentences_filings(
        summary_text,
        max_sentences=_closing_sentence_cap_for_target(
            target_length, include_health_rating=include_health_rating
        ),
    )
    summary_text = _merge_duplicate_canonical_sections(
        summary_text, include_health_rating=include_health_rating
    )
    post_underweight_titles, _ = _short_underweight_section_guidance(
        summary_text,
        target_length=target,
        include_health_rating=include_health_rating,
    )
    post_rebalance_flags: Dict[str, Any] = {
        "section_balance_issue": True,
        "section_balance_underweight_titles": list(post_underweight_titles[:4]),
    }
    summary_text, post_rebalance_info = _rebalance_section_budgets_deterministically(
        summary_text,
        target_length=target,
        include_health_rating=include_health_rating,
        section_balance_contract_required=True,
        issue_flags=post_rebalance_flags,
        generation_stats=generation_stats,
        calculated_metrics=calculated_metrics,
    )
    summary_text = _ensure_final_strict_word_band(
        summary_text,
        target,
        include_health_rating=include_health_rating,
        tolerance=tolerance,
        generation_stats=generation_stats,
        allow_padding=False,
    )
    summary_text = _enforce_whitespace_word_band(
        summary_text,
        target,
        tolerance=tolerance,
        allow_padding=False,
        dedupe=True,
    )

    final_split_wc = len((summary_text or "").split())
    final_stripped_wc = _count_words(summary_text or "")
    if final_split_wc < lower or final_stripped_wc < lower:
        # Final deterministic drift correction: append one balanced sentence
        # to the highest-priority narrative section until both counters clear.
        preferred_titles = [
            "Financial Performance",
            "Management Discussion & Analysis",
            "Risk Factors",
            "Executive Summary",
            "Closing Takeaway",
        ]
        for section_title in preferred_titles:
            if final_split_wc >= lower and final_stripped_wc >= lower:
                break
            section_body = _extract_markdown_section_body(summary_text, section_title)
            if not section_body:
                continue
            addition = _next_unique_section_balance_top_up_sentence(
                section_body,
                section_title=section_title,
                attempt=0,
                calculated_metrics=calculated_metrics,
                health_score_data=None,
                risk_factors_excerpt="",
            )
            if not addition:
                continue
            updated_body = _append_section_balance_sentence(
                section_body,
                section_title=section_title,
                sentence=addition,
            )
            if updated_body == section_body:
                continue
            summary_text = _replace_markdown_section_body(
                summary_text,
                section_title,
                updated_body,
            )
            summary_text = _enforce_whitespace_word_band(
                summary_text,
                target,
                tolerance=tolerance,
                allow_padding=False,
                dedupe=True,
            )
            final_split_wc = len((summary_text or "").split())
            final_stripped_wc = _count_words(summary_text or "")
    if generation_stats is not None:
        generation_stats["short_underflow_rescue_post_rebalance_applied"] = bool(
            post_rebalance_info.get("applied")
        )
        generation_stats["short_underflow_rescue_post_rebalance_words_added"] = int(
            post_rebalance_info.get("words_added", 0) or 0
        )
        generation_stats["short_underflow_rescue_post_rebalance_words_trimmed"] = int(
            post_rebalance_info.get("words_trimmed", 0) or 0
        )
        generation_stats["short_underflow_rescue_post_rebalance_expanded_sections"] = (
            list(post_rebalance_info.get("expanded_sections") or [])
        )
        generation_stats["short_underflow_rescue_expanded_sections"] = list(
            dict.fromkeys(
                list(pre_rebalance_info.get("expanded_sections") or [])
                + list(post_rebalance_info.get("expanded_sections") or [])
            )
        )
        generation_stats["short_underflow_rescue_in_band"] = bool(
            lower <= final_split_wc <= upper and lower <= final_stripped_wc <= upper
        )
        generation_stats["short_underflow_rescue_targets"] = list(
            underweight_titles[:4]
        )
        generation_stats["short_underflow_rescue_final_split_words"] = int(
            final_split_wc
        )
        generation_stats["short_underflow_rescue_final_stripped_words"] = int(
            final_stripped_wc
        )
    return summary_text


def _regenerate_short_form_sections_from_pipeline_evidence(
    summary_text: str,
    *,
    target_length: Optional[int],
    include_health_rating: bool,
    issue_flags: Optional[Dict[str, Any]] = None,
    regenerate_section_fn: Optional[Callable[..., str]] = None,
    generation_stats: Optional[Dict[str, Any]] = None,
    max_sections: int = 2,
) -> Tuple[str, Dict[str, Any]]:
    text = (summary_text or "").strip()
    info: Dict[str, Any] = {
        "changed": False,
        "applied": False,
        "actions": [],
        "regenerated_sections": [],
    }
    if not text or not target_length or regenerate_section_fn is None:
        return summary_text, info
    if not _is_short_mid_precision_target(target_length):
        return summary_text, info

    flags = issue_flags or {}
    if flags.get("quote_issue") or flags.get("key_metrics_issue"):
        return summary_text, info

    band = _target_word_band_bounds(target_length)
    if band is None:
        return summary_text, info
    lower_total, _upper_total, _tolerance = band
    budgets = _calculate_section_word_budgets(
        int(target_length), include_health_rating=include_health_rating
    )
    if not budgets:
        return summary_text, info
    counts = _collect_section_body_word_counts(
        text, include_health_rating=include_health_rating
    )
    current_total = _count_words(text)
    narrative_titles = [
        title
        for title in _SUMMARY_NARRATIVE_REPETITION_SECTIONS
        if title != "Key Metrics"
        and (include_health_rating or title != "Financial Health Rating")
    ]
    preferred = [
        title
        for title in list(flags.get("section_balance_underweight_titles") or [])
        if title in narrative_titles
    ]
    recipients = list(dict.fromkeys(preferred))
    for title in sorted(
        narrative_titles,
        key=lambda item: (
            item not in recipients,
            -max(0, int(budgets.get(item, 0) or 0) - int(counts.get(item, 0) or 0)),
        ),
    ):
        if title not in recipients:
            recipients.append(title)

    sections_attempted = 0
    for section_title in recipients:
        if sections_attempted >= max(1, int(max_sections or 1)):
            break
        body = _extract_markdown_section_body(text, section_title)
        if body is None:
            continue
        budget = int(budgets.get(section_title, 0) or 0)
        if budget <= 0:
            continue
        observed = int(counts.get(section_title, 0) or 0)
        section_tol = _section_budget_tolerance_words(budget, max_tolerance=10)
        lower_section = max(1, int(budget) - int(section_tol))
        upper_section = int(budget) + int(section_tol)
        room = max(0, int(upper_section) - int(observed))
        total_deficit = max(0, int(lower_total) - int(current_total))
        section_deficit = max(0, int(lower_section) - int(observed))
        if room <= 0:
            continue
        if section_deficit <= 0 and total_deficit <= 0 and section_title not in preferred:
            continue

        requested_addition = max(section_deficit, min(room, total_deficit))
        failure_reason = (
            f"Continuous-V2 filing-evidence repair for {section_title}.\n"
            f"- Actual word count: {observed}\n"
            f"- Required range: {lower_section}-{upper_section}\n"
            f"- Add approximately {max(8, requested_addition)} new body words while staying inside the section range.\n"
        )
        if total_deficit > 0:
            failure_reason += (
                f"- The full memo is {total_deficit} words below the lower bound {lower_total}; "
                "help close that gap inside this section before any generic fallback is considered.\n"
            )
        failure_reason += (
            "- Expand with unused company terms, management expectations, promise scorecard items, "
            "or filing-grounded evidence.\n"
            "- Do not restate prior claims, do not add generic finance filler, and do not add bullets or mini-headings.\n"
        )
        section_memory = _collect_section_memory(text, include_health_rating)
        new_body = str(
            regenerate_section_fn(
                section_name=section_title,
                budget=budget,
                failure_reason=failure_reason,
                prior_section_text=_previous_section_text(
                    text, section_title, include_health_rating
                ),
                existing_section_text=str(body or ""),
                used_claims=list(section_memory.get("used_claims") or []),
                section_memory=section_memory,
            )
            or ""
        ).strip()
        if not new_body:
            continue
        new_count = _count_words(new_body)
        new_section_deficit = max(0, int(lower_section) - int(new_count))
        new_section_overage = max(0, int(new_count) - int(upper_section))
        old_section_deficit = max(0, int(lower_section) - int(observed))
        old_section_overage = max(0, int(observed) - int(upper_section))
        improved = (
            new_section_overage <= old_section_overage
            and (
                new_section_deficit < old_section_deficit
                or (new_count > observed and total_deficit > 0)
            )
        )
        if not improved:
            continue

        text = _replace_markdown_section_body(text, section_title, new_body)
        current_total += max(0, int(new_count) - int(observed))
        counts[section_title] = int(new_count)
        info["changed"] = True
        info["applied"] = True
        info["regenerated_sections"].append(section_title)
        sections_attempted += 1
        if current_total >= int(lower_total) and not max(
            0, int(lower_section) - int(new_count)
        ):
            break

    if info["applied"]:
        info["regenerated_sections"] = list(
            dict.fromkeys(info["regenerated_sections"])
        )
        info["actions"].append("short_contract_pipeline_evidence_regeneration")
        if generation_stats is not None:
            generation_stats["short_contract_pipeline_evidence_regeneration_used"] = (
                True
            )
            generation_stats["short_contract_pipeline_evidence_regeneration_sections"] = list(
                {
                    *(
                        generation_stats.get(
                            "short_contract_pipeline_evidence_regeneration_sections",
                            [],
                        )
                        or []
                    ),
                    *(info["regenerated_sections"] or []),
                }
            )
            generation_stats.setdefault("editorial_repair_actions", []).extend(
                info["actions"]
            )
    return text, info


def _recover_short_form_editorial_issues_once(
    summary_text: str,
    *,
    target_length: int,
    include_health_rating: bool,
    missing_requirements: Optional[List[str]],
    quality_profile: SummaryFlowQualityProfile,
    quality_validators: Optional[List[Callable[[str], Optional[str]]]],
    calculated_metrics: Dict[str, Any],
    company_name: str,
    source_text: Optional[str],
    filing_language_snippets: str,
    enforce_quote_contract: bool,
    gemini_client: Optional[Any],
    health_score_data: Optional[Dict[str, Any]] = None,
    risk_factors_excerpt: str = "",
    generation_stats: Optional[Dict[str, Any]] = None,
    token_budget: Optional[TokenBudget] = None,
    cost_budget: Optional[SummaryCostBudget] = None,
    max_output_tokens: int = DEFAULT_OPENAI_MAX_OUTPUT_TOKENS,
    persona_intensity: str = "strong",
    pipeline_section_regenerator: Optional[Callable[..., str]] = None,
) -> Tuple[str, List[str], Dict[str, Any], bool]:
    """Run one bounded short-form editorial recovery attempt before downgrading warnings."""
    text = str(summary_text or "").strip()
    if not text:
        return (
            summary_text,
            list(missing_requirements or []),
            {"final_word_count": 0},
            False,
        )
    if not _is_short_mid_precision_target(target_length):
        rechecked_missing, rechecked_meta = _evaluate_summary_contract_requirements(
            summary_text=text,
            target_length=target_length,
            include_health_rating=include_health_rating,
            quality_validators=quality_validators,
            source_text=source_text,
            filing_language_snippets=filing_language_snippets,
            enforce_quote_contract=enforce_quote_contract,
        )
        return text, rechecked_missing, rechecked_meta, False

    attempted = False
    rewrite_used = False

    def _repair_applied(info: Optional[Dict[str, Any]]) -> bool:
        payload = info if isinstance(info, dict) else {}
        return bool(payload.get("changed") or payload.get("applied"))

    parsed_flags = _parse_summary_contract_missing_requirements(missing_requirements)

    text, editorial_info = _apply_editorial_contract_repairs(
        text,
        target_length=target_length,
        include_health_rating=include_health_rating,
        quality_profile=quality_profile,
        missing_requirements=list(missing_requirements or []),
        issue_flags=parsed_flags,
        generation_stats=generation_stats,
    )
    if editorial_info.get("actions"):
        attempted = True

    if parsed_flags.get("leading_word_repetition_issue"):
        text, lwr_info = _repair_leading_word_repetition_in_summary(
            text,
            max_same_opening=max(
                1, int(getattr(quality_profile, "max_same_opening", 2) or 2)
            ),
            target_sections=list(
                parsed_flags.get("leading_word_repetition_sections") or []
            ),
        )
        if lwr_info.get("changed"):
            attempted = True

    text, brief_section_info = _repair_brief_sections_deterministically(
        text,
        missing_requirements=list(missing_requirements or []),
        calculated_metrics=calculated_metrics,
        health_score_data=health_score_data,
        risk_factors_excerpt=risk_factors_excerpt,
        generation_stats=generation_stats,
    )
    if brief_section_info.get("applied"):
        attempted = True

    if parsed_flags.get("management_voice_issue"):
        text, exec_voice_info = _repair_executive_summary_management_voice_from_snippets(
            text,
            filing_language_snippets=filing_language_snippets,
            target_length=target_length,
        )
        if _repair_applied(exec_voice_info):
            attempted = True
        text, voice_info = _repair_mdna_management_voice_from_snippets(
            text,
            filing_language_snippets=filing_language_snippets,
            target_length=target_length,
        )
        if _repair_applied(voice_info):
            attempted = True

        text, closing_voice_info = _repair_closing_takeaway_management_voice_from_snippets(
            text,
            filing_language_snippets=filing_language_snippets,
            target_length=target_length,
        )
        if _repair_applied(closing_voice_info):
            attempted = True

    if parsed_flags.get("bridge_issue"):
        bridged = _ensure_section_transition_handoffs(
            text,
            include_health_rating=include_health_rating,
            target_length=target_length,
        )
        if bridged != text:
            text = bridged
            attempted = True

    if gemini_client is not None:
        rewrite_hint = (
            "Short-form editorial recovery: fix repetition and style issues while preserving "
            "headings, quotes, numeric facts, Key Metrics rows, and stance."
        )
        if parsed_flags.get("section_balance_issue"):
            balance_guidance = _build_precision_section_balance_guidance(
                summary_text=text,
                target_length=target_length,
                include_health_rating=include_health_rating,
                missing_requirements=list(missing_requirements or []),
            )
            if balance_guidance:
                rewrite_hint += (
                    "\nRebalance section budgets by expanding underweight narrative sections first "
                    "and tightening overweight sections proportionally.\n"
                    + balance_guidance
                )
        emergency_rewrite_stats: Optional[Dict[str, Any]] = generation_stats
        if generation_stats is not None:
            rewrite_calls = int(generation_stats.get("rewrite_call_count", 0) or 0)
            if rewrite_calls >= int(MAX_REWRITE_ATTEMPTS):
                emergency_rewrite_stats = None
        rewritten_text, _ = _rewrite_summary_to_length(
            gemini_client,
            text,
            int(target_length),
            quality_validators,
            current_words=_count_words(text or ""),
            token_budget=token_budget,
            cost_budget=cost_budget,
            max_output_tokens=max_output_tokens,
            generation_stats=emergency_rewrite_stats,
            persona_intensity=persona_intensity,
            quality_issue_hint=rewrite_hint,
            allow_over_target_recovery=True,
            ignore_max_rewrite_attempts=True,
            timeout_seconds=_summary_rewrite_timeout_seconds(),
        )
        if rewritten_text and rewritten_text.strip():
            text = rewritten_text
            rewrite_used = True
            attempted = True
            if emergency_rewrite_stats is None and generation_stats is not None:
                generation_stats["short_editorial_reserved_rewrite_used"] = True

    if attempted:
        text = _run_summary_cleanup_pass(
            text,
            include_health_rating=include_health_rating,
            calculated_metrics=calculated_metrics,
            company_name=company_name,
        )
        text = _fix_inline_section_headers(text)
        text = _normalize_section_headings(
            text,
            include_health_rating=include_health_rating,
        )
        text = _remove_metric_echo_loops(text)
        text = _merge_staccato_paragraphs(text)
        text = _cap_closing_sentences_filings(
            text,
            max_sentences=_closing_sentence_cap_for_target(
                target_length, include_health_rating=include_health_rating
            ),
        )
        text = _merge_duplicate_canonical_sections(
            text, include_health_rating=include_health_rating
        )
        text = _enforce_section_order(text, include_health_rating=include_health_rating)
        repair_metrics_lines = _build_key_metrics_block(
            calculated_metrics or {},
            target_length=target_length,
            include_health_rating=include_health_rating,
            health_score_data=health_score_data,
        )
        text = _apply_short_form_structural_seal(
            text,
            include_health_rating=include_health_rating,
            metrics_lines=repair_metrics_lines,
            calculated_metrics=calculated_metrics or {},
            company_name=company_name,
            risk_factors_excerpt=risk_factors_excerpt,
            health_score_data=health_score_data,
            health_rating_config=None,
            persona_name=None,
            persona_requested=False,
            target_length=target_length,
        )
        if (repair_metrics_lines or "").strip():
            text = _canonicalize_key_metrics_section(text, repair_metrics_lines)
        band = _target_word_band_bounds(target_length)
        if band is not None:
            _lower, _upper, tolerance = band
            text = _ensure_final_strict_word_band(
                text,
                int(target_length),
                include_health_rating=include_health_rating,
                tolerance=int(tolerance),
                generation_stats=generation_stats,
                allow_padding=False,
            )
            text = _enforce_whitespace_word_band(
                text,
                int(target_length),
                tolerance=int(tolerance),
                allow_padding=False,
                dedupe=True,
            )
            text = _tighten_short_mid_precision_target(
                text,
                target_length=target_length,
                include_health_rating=include_health_rating,
                generation_stats=generation_stats,
            )

    def _recheck_contract(current_text: str) -> Tuple[List[str], Dict[str, Any]]:
        return _evaluate_summary_contract_requirements(
            summary_text=current_text,
            target_length=target_length,
            include_health_rating=include_health_rating,
            quality_validators=quality_validators,
            source_text=source_text,
            filing_language_snippets=filing_language_snippets,
            enforce_quote_contract=enforce_quote_contract,
        )

    rechecked_missing, rechecked_meta = _recheck_contract(text)
    rechecked_flags = _parse_summary_contract_missing_requirements(rechecked_missing)
    deterministic_rescue_applied = False
    text, rechecked_brief_info = _repair_brief_sections_deterministically(
        text,
        missing_requirements=rechecked_missing,
        calculated_metrics=calculated_metrics,
        health_score_data=health_score_data,
        risk_factors_excerpt=risk_factors_excerpt,
        generation_stats=generation_stats,
    )
    if _repair_applied(rechecked_brief_info):
        attempted = True
        deterministic_rescue_applied = True
        rechecked_missing, rechecked_meta = _recheck_contract(text)
        rechecked_flags = _parse_summary_contract_missing_requirements(
            rechecked_missing
        )
    if rechecked_flags.get("management_voice_issue"):
        text, rechecked_exec_voice_info = (
            _repair_executive_summary_management_voice_from_snippets(
                text,
                filing_language_snippets=filing_language_snippets,
                target_length=target_length,
            )
        )
        if _repair_applied(rechecked_exec_voice_info):
            attempted = True
            deterministic_rescue_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )
        text, rechecked_voice_info = _repair_mdna_management_voice_from_snippets(
            text,
            filing_language_snippets=filing_language_snippets,
            target_length=target_length,
        )
        if _repair_applied(rechecked_voice_info):
            attempted = True
            deterministic_rescue_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )
        text, rechecked_closing_voice_info = (
            _repair_closing_takeaway_management_voice_from_snippets(
                text,
                filing_language_snippets=filing_language_snippets,
                target_length=target_length,
            )
        )
        if _repair_applied(rechecked_closing_voice_info):
            attempted = True
            deterministic_rescue_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )
    if rechecked_flags.get("bridge_issue"):
        bridged = _ensure_section_transition_handoffs(
            text,
            include_health_rating=include_health_rating,
            target_length=target_length,
        )
        if bridged != text:
            text = bridged
            attempted = True
            deterministic_rescue_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )
    text, key_metrics_info = _repair_short_form_key_metrics_underflow(
        text,
        target_length=target_length,
        include_health_rating=include_health_rating,
        calculated_metrics=calculated_metrics,
        health_score_data=health_score_data,
        generation_stats=generation_stats,
    )
    if _repair_applied(key_metrics_info):
        attempted = True
        deterministic_rescue_applied = True
        rechecked_missing, rechecked_meta = _recheck_contract(text)
        rechecked_flags = _parse_summary_contract_missing_requirements(
            rechecked_missing
        )

    if pipeline_section_regenerator is not None and (
        rechecked_flags.get("section_balance_issue")
        or rechecked_flags.get("word_band_issue")
    ):
        text, pipeline_regen_info = _regenerate_short_form_sections_from_pipeline_evidence(
            text,
            target_length=target_length,
            include_health_rating=include_health_rating,
            issue_flags=rechecked_flags,
            regenerate_section_fn=pipeline_section_regenerator,
            generation_stats=generation_stats,
        )
        if _repair_applied(pipeline_regen_info):
            attempted = True
            deterministic_rescue_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )

    should_use_deterministic_balance_repair = bool(
        rechecked_flags.get("section_balance_issue")
        and (
            pipeline_section_regenerator is None
            or bool(rechecked_flags.get("section_balance_overweight_titles"))
        )
    )
    if should_use_deterministic_balance_repair:
        text, rebalance_info = _rebalance_section_budgets_deterministically(
            text,
            target_length=target_length,
            include_health_rating=include_health_rating,
            section_balance_contract_required=True,
            issue_flags=rechecked_flags,
            generation_stats=generation_stats,
            calculated_metrics=calculated_metrics,
            health_score_data=health_score_data,
            risk_factors_excerpt=risk_factors_excerpt,
        )
        if _repair_applied(rebalance_info):
            attempted = True
            deterministic_rescue_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )

    should_use_deterministic_underflow_repair = bool(
        pipeline_section_regenerator is None
    )
    if (
        should_use_deterministic_underflow_repair
        and rechecked_flags.get("word_band_issue")
        and not _has_hard_risk_issue(rechecked_flags)
    ):
        text, top_up_info = _precise_short_contract_underflow_top_up(
            text,
            target_length=target_length,
            include_health_rating=include_health_rating,
            issue_flags=rechecked_flags,
            generation_stats=generation_stats,
        )
        if _repair_applied(top_up_info):
            attempted = True
            deterministic_rescue_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )

    if should_use_deterministic_underflow_repair and rechecked_flags.get(
        "word_band_issue"
    ):
        text, expand_info = _expand_narrative_sections_for_short_contract_underflow(
            text,
            target_length=target_length,
            include_health_rating=include_health_rating,
            issue_flags=rechecked_flags,
            generation_stats=generation_stats,
            calculated_metrics=calculated_metrics,
            health_score_data=health_score_data,
            risk_factors_excerpt=risk_factors_excerpt,
        )
        if _repair_applied(expand_info):
            attempted = True
            deterministic_rescue_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )

    if deterministic_rescue_applied:
        text = _enforce_section_order(text, include_health_rating=include_health_rating)
        band = _target_word_band_bounds(target_length)
        if band is not None:
            _lower, _upper, tolerance = band
            text = _ensure_final_strict_word_band(
                text,
                int(target_length),
                include_health_rating=include_health_rating,
                tolerance=int(tolerance),
                generation_stats=generation_stats,
                allow_padding=False,
            )
            text = _enforce_whitespace_word_band(
                text,
                int(target_length),
                tolerance=int(tolerance),
                allow_padding=False,
                dedupe=True,
            )
            text = _tighten_short_mid_precision_target(
                text,
                target_length=target_length,
                include_health_rating=include_health_rating,
                generation_stats=generation_stats,
            )
        rechecked_missing, rechecked_meta = _recheck_contract(text)
        rechecked_flags = _parse_summary_contract_missing_requirements(
            rechecked_missing
        )

    residual_editorial_applied = False
    if rechecked_flags.get("needs_editorial_deterministic_repair"):
        text, residual_editorial_info = _apply_editorial_contract_repairs(
            text,
            target_length=target_length,
            include_health_rating=include_health_rating,
            quality_profile=quality_profile,
            missing_requirements=list(rechecked_missing or []),
            issue_flags=rechecked_flags,
            generation_stats=generation_stats,
        )
        if _repair_applied(residual_editorial_info):
            attempted = True
            residual_editorial_applied = True
            rechecked_missing, rechecked_meta = _recheck_contract(text)
            rechecked_flags = _parse_summary_contract_missing_requirements(
                rechecked_missing
            )

    text, residual_brief_info = _repair_brief_sections_deterministically(
        text,
        missing_requirements=rechecked_missing,
        calculated_metrics=calculated_metrics,
        health_score_data=health_score_data,
        risk_factors_excerpt=risk_factors_excerpt,
        generation_stats=generation_stats,
    )
    if _repair_applied(residual_brief_info):
        attempted = True
        residual_editorial_applied = True
        rechecked_missing, rechecked_meta = _recheck_contract(text)
        rechecked_flags = _parse_summary_contract_missing_requirements(
            rechecked_missing
        )

    if residual_editorial_applied:
        text = _enforce_section_order(text, include_health_rating=include_health_rating)
        text = _tighten_short_mid_precision_target(
            text,
            target_length=target_length,
            include_health_rating=include_health_rating,
            generation_stats=generation_stats,
        )
        rechecked_missing, rechecked_meta = _recheck_contract(text)

    if generation_stats is not None:
        generation_stats["short_form_editorial_recovery_attempted"] = bool(attempted)
        generation_stats["short_form_editorial_recovery_rewrite_used"] = bool(
            rewrite_used
        )
    return text, rechecked_missing, rechecked_meta, attempted


def _parse_summary_contract_missing_requirements(
    missing_requirements: Optional[List[str]],
) -> Dict[str, Any]:
    flags: Dict[str, Any] = {
        "word_band_issue": False,
        "quote_distribution_issue": False,
        "quote_grounding_issue": False,
        "quote_evidence_gap": False,
        "quote_issue": False,
        "bridge_issue": False,
        "closing_trigger_issue": False,
        "section_balance_issue": False,
        "key_metrics_issue": False,
        "section_balance_underweight_titles": [],
        "section_balance_overweight_titles": [],
        "number_repetition_issue": False,
        "theme_repetition_issue": False,
        "question_framing_repetition_issue": False,
        "leading_word_repetition_issue": False,
        "leading_word_repetition_sections": [],
        "numbers_discipline_issue": False,
        "numbers_discipline_sections": [],
        "closing_parenthetical_issue": False,
        "duplicate_sentence_issue": False,
        "near_duplicate_paragraph_issue": False,
        "section_repetition_issue": False,
        "risk_schema_issue": False,
        "risk_specificity_issue": False,
        "management_voice_issue": False,
        "editorial_quality_issue": False,
        "needs_editorial_deterministic_repair": False,
        "needs_deterministic_repair": False,
    }
    section_balance_re = re.compile(
        r"section balance issue:\s*'([^']+)'\s+is\s+(underweight|overweight)",
        re.IGNORECASE,
    )
    numbers_discipline_section_re = re.compile(
        r"numbers discipline:\s*([^:]+?)\s+is\s+too\s+numeric",
        re.IGNORECASE,
    )
    leading_word_repetition_re = re.compile(
        r"leading-word repetition in\s+([^:]+?)\s*:",
        re.IGNORECASE,
    )
    risk_schema_snippets = (
        "risk factors are not in the required format",
        "risk factors contain duplicate risk names",
        "risk factors repeat the same generic risk family",
        "overlaps too much with a previous risk",
        "body is too similar to a previous risk body",
        "risk factors are too thin under",
        "need a concrete mechanism",
        "must explain the financial impact path",
        "must contain 2-3 sentences",
        "must contain 3-4 sentences",
    )
    for item in missing_requirements or []:
        raw = str(item or "")
        normalized = " ".join(raw.split()).strip().lower()
        if not normalized:
            continue
        if "word-count band violation" in normalized:
            flags["word_band_issue"] = True
        if "verified direct quote" in normalized or (
            "verified short direct quote" in normalized
            and "executive summary/md&a" in normalized
        ):
            flags["quote_distribution_issue"] = True
        if "quoted phrase is not grounded in filing text" in normalized:
            flags["quote_grounding_issue"] = True
        if "insufficient filing-language evidence for quote contract" in normalized:
            flags["quote_evidence_gap"] = True
        if "explicit bridge into" in normalized or "conceptual handoff into" in normalized:
            flags["bridge_issue"] = True
        if "closing takeaway" in normalized and (
            "trigger" in normalized
            or "what must stay true" in normalized
            or "what breaks the thesis" in normalized
        ):
            flags["closing_trigger_issue"] = True
        if "key metrics" in normalized or "data_grid" in normalized:
            flags["key_metrics_issue"] = True
        if "section balance issue:" in normalized:
            flags["section_balance_issue"] = True
            match = section_balance_re.search(raw)
            if match:
                title = str(match.group(1) or "").strip()
                direction = str(match.group(2) or "").strip().lower()
                key = (
                    "section_balance_underweight_titles"
                    if direction == "underweight"
                    else "section_balance_overweight_titles"
                )
                existing = set(flags.get(key) or [])
                if title and title not in existing:
                    flags[key].append(title)
        if "number repetition across sections:" in normalized:
            flags["number_repetition_issue"] = True
        if (
            "cross-section dollar figure repetition:" in normalized
            or "repeats dollar figures already used in earlier sections" in normalized
        ):
            flags["number_repetition_issue"] = True
        if "theme over-repetition:" in normalized:
            flags["theme_repetition_issue"] = True
        if (
            "recycling too many of the same themes" in normalized
            or "leaning on generic repeated themes" in normalized
            or "is replaying financial performance themes" in normalized
        ):
            flags["theme_repetition_issue"] = True
        if "question-framing repetition:" in normalized:
            flags["question_framing_repetition_issue"] = True
        if "leading-word repetition in" in normalized:
            flags["leading_word_repetition_issue"] = True
            lwr_match = leading_word_repetition_re.search(raw)
            if lwr_match:
                section_title = " ".join(str(lwr_match.group(1) or "").split()).strip()
                if section_title:
                    existing_sections = set(
                        flags.get("leading_word_repetition_sections") or []
                    )
                    if section_title not in existing_sections:
                        flags["leading_word_repetition_sections"].append(section_title)
        if "numbers discipline:" in normalized:
            flags["numbers_discipline_issue"] = True
            numbers_match = numbers_discipline_section_re.search(raw)
            if numbers_match:
                section_title = " ".join(
                    str(numbers_match.group(1) or "").split()
                ).strip()
                if section_title:
                    existing_sections = set(
                        flags.get("numbers_discipline_sections") or []
                    )
                    if section_title not in existing_sections:
                        flags["numbers_discipline_sections"].append(section_title)
        if "closing takeaway" in normalized and "parenthetical" in normalized:
            flags["closing_parenthetical_issue"] = True
        if "duplicate sentences detected" in normalized:
            flags["duplicate_sentence_issue"] = True
        if "near-duplicate paragraphs detected" in normalized:
            flags["near_duplicate_paragraph_issue"] = True
        if "contains repeated analytical content" in normalized:
            flags["section_repetition_issue"] = True
        if (
            "risk factors has" in normalized
            and "structured risk(s);" in normalized
            and "expected exactly" in normalized
        ):
            flags["risk_schema_issue"] = True
        if "risk factors lack filing grounding" in normalized:
            flags["risk_specificity_issue"] = True
        if _is_risk_specificity_requirement(normalized):
            flags["risk_specificity_issue"] = True
        elif any(snippet in normalized for snippet in risk_schema_snippets):
            flags["risk_schema_issue"] = True
        if (
            "management voice" in normalized
            or "clear management attribution" in normalized
        ):
            flags["management_voice_issue"] = True
    flags["quote_issue"] = bool(
        flags["quote_distribution_issue"]
        or flags["quote_grounding_issue"]
        or flags["quote_evidence_gap"]
    )
    flags["editorial_quality_issue"] = bool(
        flags["number_repetition_issue"]
        or flags["theme_repetition_issue"]
        or flags["question_framing_repetition_issue"]
        or flags["leading_word_repetition_issue"]
        or flags["numbers_discipline_issue"]
        or flags["closing_parenthetical_issue"]
        or flags["duplicate_sentence_issue"]
        or flags["near_duplicate_paragraph_issue"]
        or flags["section_repetition_issue"]
        or flags["section_balance_issue"]
    )
    flags["needs_editorial_deterministic_repair"] = bool(
        flags["number_repetition_issue"]
        or flags["theme_repetition_issue"]
        or flags["question_framing_repetition_issue"]
        or flags["leading_word_repetition_issue"]
        or flags["numbers_discipline_issue"]
        or flags["closing_parenthetical_issue"]
        or flags["duplicate_sentence_issue"]
        or flags["near_duplicate_paragraph_issue"]
        or flags["section_repetition_issue"]
    )
    flags["needs_deterministic_repair"] = bool(
        flags["quote_distribution_issue"]
        or flags["bridge_issue"]
        or flags["closing_trigger_issue"]
        or flags["key_metrics_issue"]
        or flags["risk_schema_issue"]
        or flags["risk_specificity_issue"]
        or flags["management_voice_issue"]
    )
    return flags


def _select_short_form_structural_failure_requirements(
    *,
    summary_text: str,
    missing_requirements: Optional[List[str]],
    include_health_rating: bool,
    enforce_section_balance: bool = False,
) -> List[str]:
    """Select structural failures that must remain fatal for short sectioned memos."""
    text = str(summary_text or "").strip()
    items = [
        str(item) for item in (missing_requirements or []) if str(item or "").strip()
    ]
    if not text:
        return items

    required_titles = [
        title
        for title, _minimum in SUMMARY_SECTION_REQUIREMENTS
        if include_health_rating or title != "Financial Health Rating"
    ]
    allowed_titles = set(required_titles)
    heading_re = re.compile(r"^\s*##\s+(.+?)\s*$", re.MULTILINE)
    existing_by_norm = {" ".join(item.split()).strip().lower(): item for item in items}
    fatal: List[str] = []
    seen_norms: Set[str] = set()

    def _append(requirement: str) -> None:
        normalized = " ".join(str(requirement or "").split()).strip().lower()
        if not normalized or normalized in seen_norms:
            return
        seen_norms.add(normalized)
        fatal.append(requirement)

    def _append_matching(default_requirement: str, *snippets: str) -> None:
        snippet_norms = [
            " ".join(str(snippet or "").split()).strip().lower()
            for snippet in snippets
            if str(snippet or "").strip()
        ]
        for normalized, original in existing_by_norm.items():
            if any(snippet in normalized for snippet in snippet_norms):
                _append(original)
                return
        _append(default_requirement)

    seen_titles: Set[str] = set()
    for match in heading_re.finditer(text):
        raw_heading = (match.group(1) or "").strip()
        canon = _standard_section_name_from_heading(f"## {raw_heading}")
        if canon in seen_titles and canon in allowed_titles:
            _append_matching(
                (
                    f"Duplicate section heading detected: '## {raw_heading}'. "
                    "Each required section may appear only once. Merge duplicate content into a single canonical section."
                ),
                "duplicate section heading detected",
            )
        seen_titles.add(canon)
        if canon not in allowed_titles:
            _append_matching(
                (
                    f"Extra section heading detected: '## {raw_heading}'. "
                    "Only use the required canonical memo headings."
                ),
                "extra section heading detected",
            )

    for title in required_titles:
        body = _extract_markdown_section_body(text, title)
        if body is not None and body.strip():
            continue
        _append_matching(
            f"Missing the heading '## {title}'. Use that exact markdown heading (no prefixes) and include substantive content beneath it.",
            f"missing the heading '## {title.lower()}",
            f"the '{title.lower()}' section is too brief",
        )

    key_metrics_body = _extract_markdown_section_body(text, "Key Metrics") or ""
    key_metrics_issue, key_metrics_numeric_rows = _validate_key_metrics_numeric_block(
        key_metrics_body,
        min_rows=5,
        require_markers=True,
    )
    # Fallback: accept valid numeric rows even without DATA_GRID markers.
    if key_metrics_issue and "Missing DATA_GRID" in str(key_metrics_issue):
        key_metrics_issue, key_metrics_numeric_rows = _validate_key_metrics_numeric_block(
            key_metrics_body,
            min_rows=5,
            require_markers=False,
        )
    if key_metrics_issue:
        if key_metrics_numeric_rows < 5:
            _append_matching(
                key_metrics_issue,
                "key metrics must include at least 5 numeric rows",
            )
        else:
            _append_matching(
                key_metrics_issue,
                "key metrics must be numeric data_grid rows only",
                "data_grid",
            )

    closing_body = _extract_markdown_section_body(text, "Closing Takeaway") or ""
    if closing_body and not re.search(r"\b(buy|hold|sell)\b", closing_body, re.IGNORECASE):
        _append_matching(
            "Closing Takeaway is missing an explicit Buy/Hold/Sell recommendation.",
            "closing takeaway is missing an explicit buy/hold/sell recommendation",
        )

    if _summary_has_incomplete_tail(text):
        _append_matching(
            "Final summary still ends mid-thought after cleanup. Finish the closing sentence cleanly.",
            "the 'closing takeaway' section is too brief",
            "final summary still ends mid-thought",
        )

    if enforce_section_balance:
        appended = False
        for item in items:
            normalized = " ".join(str(item).split()).strip().lower()
            if "section balance issue:" not in normalized:
                continue
            _append(item)
            appended = True
        if not appended:
            parsed_flags = _parse_summary_contract_missing_requirements(items)
            if parsed_flags.get("section_balance_issue"):
                _append(
                    "Section balance issue remains unresolved after bounded recovery; narrative sections must align with target-aware budgets."
                )

    return fatal


def _select_short_form_editorial_failure_requirements(
    *,
    missing_requirements: Optional[List[str]],
) -> List[str]:
    """Keep short summaries clean by failing unresolved editorial slop after repair."""
    items = [
        str(item) for item in (missing_requirements or []) if str(item or "").strip()
    ]
    if not items:
        return []

    fatal_snippets = (
        "verbatim repetition detected",
        "question-framing repetition",
        "theme over-repetition",
        "number repetition across sections",
        "leading-word repetition",
        "section is too brief",
        "generic filler detected",
        "excessive generic filler",
        "instruction leak detected",
        "forbidden phrase detected",
        "over-repetition detected",
        "repetition-by-structure detected",
    )
    fatal: List[str] = []
    seen: Set[str] = set()
    for item in items:
        normalized = " ".join(item.split()).strip().lower()
        if not normalized:
            continue
        if any(snippet in normalized for snippet in fatal_snippets):
            if normalized not in seen:
                seen.add(normalized)
                fatal.append(item)
    return fatal


def _select_short_form_editorial_hard_failure_requirements(
    *,
    missing_requirements: Optional[List[str]],
) -> List[str]:
    """Escalate unresolved short-form editorial misses that make the memo feel templated."""
    items = [
        str(item) for item in (missing_requirements or []) if str(item or "").strip()
    ]
    if not items:
        return []

    hard_fail_snippets = (
        "section is too brief",
        "generic filler detected",
        "excessive generic filler",
        "question-framing repetition",
        "theme over-repetition",
        "number repetition across sections",
    )
    hard_fail: List[str] = []
    seen: Set[str] = set()
    for item in items:
        normalized = " ".join(item.split()).strip().lower()
        if not normalized:
            continue
        if any(snippet in normalized for snippet in hard_fail_snippets):
            if normalized not in seen:
                seen.add(normalized)
                hard_fail.append(item)
    return hard_fail


def _select_continuous_v2_hard_failure_requirements(
    *,
    summary_text: str,
    missing_requirements: Optional[List[str]],
    include_health_rating: bool,
) -> List[str]:
    """Filter CV2 misses down to unresolved hard contract/editorial failures."""
    items = [
        str(item) for item in (missing_requirements or []) if str(item or "").strip()
    ]
    if not items:
        return []

    hard_fail: List[str] = []
    seen: Set[str] = set()

    def _append(item: str) -> None:
        normalized = " ".join(str(item or "").split()).strip().lower()
        if not normalized or normalized in seen:
            return
        seen.add(normalized)
        hard_fail.append(item)

    for item in _select_short_form_structural_failure_requirements(
        summary_text=summary_text,
        missing_requirements=items,
        include_health_rating=include_health_rating,
        enforce_section_balance=False,
    ):
        normalized = " ".join(str(item or "").split()).strip().lower()
        if "section balance issue:" in normalized:
            continue
        if (
            "risk factors has" in normalized
            and "structured risk(s);" in normalized
            and "expected exactly" in normalized
        ):
            continue
        _append(item)

    for item in _select_short_form_editorial_hard_failure_requirements(
        missing_requirements=items
    ):
        _append(item)

    risk_hard_snippets = (
        "risk factors contain duplicate risk names",
        "risk factors repeat the same generic risk family",
        "risk factors lack filing grounding",
    )
    hard_snippets = (
        "quoted phrase is not grounded in filing text",
        "should include either a verified direct quote or clear management attribution when filing snippets are available",
        "should include at least one forward-looking implication about what management expects, plans, or what happens next",
        "must include at least one verified direct quote",
        "period-over-period comparison",
        "financial performance must cover revenue, margin interpretation, and cash conversion",
        "should end with a conceptual handoff into",
        "must state exactly one explicit stance",
        "metric hierarchy drift in closing takeaway",
        "numbers discipline:",
    )
    for item in items:
        normalized = " ".join(str(item or "").split()).strip().lower()
        if _is_risk_specificity_requirement(normalized) or any(
            snippet in normalized for snippet in risk_hard_snippets
        ):
            _append(item)
            continue
        if any(snippet in normalized for snippet in hard_snippets):
            _append(item)

    return hard_fail


def _validated_health_score_value(value: Any) -> Optional[float]:
    try:
        score = float(value)
    except (TypeError, ValueError):
        return None
    if not math.isfinite(score):
        return None
    if score < 0 or score > 100:
        return None
    return float(score)


def _select_non_degradable_contract_requirements(
    *,
    summary_text: str,
    missing_requirements: Optional[List[str]],
    include_health_rating: bool,
) -> List[str]:
    items = [
        str(item) for item in (missing_requirements or []) if str(item or "").strip()
    ]
    fatal = _select_short_form_structural_failure_requirements(
        summary_text=summary_text,
        missing_requirements=items,
        include_health_rating=include_health_rating,
        enforce_section_balance=False,
    )
    seen = {
        " ".join(str(item or "").split()).strip().lower()
        for item in fatal
        if str(item or "").strip()
    }
    risk_schema_snippets = (
        "risk factors are not in the required format",
        "risk factors lack filing grounding",
    )

    for item in items:
        normalized = " ".join(str(item or "").split()).strip().lower()
        if not normalized:
            continue
        if _is_risk_specificity_requirement(normalized) or any(
            snippet in normalized for snippet in risk_schema_snippets
        ):
            if normalized not in seen:
                seen.add(normalized)
                fatal.append(item)
    return fatal


def _summary_payload_is_fast_cache_eligible(
    payload: Any,
    *,
    include_health_rating: bool,
) -> bool:
    if not isinstance(payload, dict):
        return False
    summary_text = str(payload.get("summary") or "").strip()
    if not summary_text:
        return False
    summary_meta = (
        payload.get("summary_meta") if isinstance(payload.get("summary_meta"), dict) else {}
    )
    missing_requirements = list(summary_meta.get("contract_missing_requirements") or [])
    if not missing_requirements:
        missing_requirements = list(payload.get("contract_warnings") or [])
    if _select_non_degradable_contract_requirements(
        summary_text=summary_text,
        missing_requirements=missing_requirements,
        include_health_rating=include_health_rating,
    ):
        return False
    if include_health_rating and _validated_health_score_value(payload.get("health_score")) is None:
        return False
    return True


def _select_one_shot_contract_failure_requirements(
    *,
    missing_requirements: Optional[List[str]],
    target_length: Optional[int],
    summary_text: Optional[str] = None,
) -> List[str]:
    """Scope one-shot hard-fail to the target-length contract only.

    For micro plaintext summaries, the full exact-word/anti-slop validator is the
    contract and every missing requirement remains fatal.

    For sectioned long-form summaries, preserve one-shot behavior but only hard-fail
    on length-band misses. Structural quote/key-metrics/section-balance checks are
    still captured in diagnostics but should not block the request in one-shot mode.
    """
    items = [
        str(item) for item in (missing_requirements or []) if str(item or "").strip()
    ]
    if _is_micro_plaintext_target(target_length):
        return items

    fatal: List[str] = []
    for item in items:
        normalized = " ".join(item.split()).strip().lower()
        if "word-count band violation" in normalized:
            fatal.append(item)
            continue
        if (
            _is_risk_specificity_requirement(normalized)
            or "risk factors lack filing grounding" in normalized
        ):
            fatal.append(item)
            continue
        if "missing the heading '## " in normalized:
            fatal.append(item)
            continue
        if "duplicate section heading detected" in normalized:
            fatal.append(item)
            continue
        if "extra section heading detected" in normalized:
            fatal.append(item)
            continue
        if (
            "consecutive duplicate token" in normalized
            or "repeated tail" in normalized
            or "tail loop" in normalized
            or "repeated ending" in normalized
        ):
            fatal.append(item)

    if target_length and summary_text:
        band = _target_word_band_bounds(target_length)
        if band is not None:
            lower, upper, _tol = band
            actual_split = len((summary_text or "").split())
            actual_stripped = _count_words(summary_text or "")
            actual_in_band = bool(
                lower <= int(actual_split) <= upper
                and lower <= int(actual_stripped) <= upper
            )
            if not actual_in_band:
                actual_band_failure = (
                    f"Final word-count band violation: expected {lower}-{upper}, "
                    f"got split={actual_split}, stripped={actual_stripped}."
                )
                if actual_band_failure not in fatal:
                    fatal.insert(0, actual_band_failure)
    return fatal


def _summary_contract_scope_for_target(target_length: Optional[int]) -> str:
    return (
        "micro_exact"
        if _is_micro_plaintext_target(target_length)
        else "long_form_one_shot"
    )


def _summary_target_band_payload(
    target_length: Optional[int],
) -> Optional[Dict[str, int]]:
    if _is_micro_plaintext_target(target_length):
        return None
    band = _target_word_band_bounds(target_length)
    if band is None:
        return None
    lower, upper, _tol = band
    return {
        "lower": int(lower),
        "upper": int(upper),
    }


def _summary_target_band_detail(
    target_length: Optional[int],
) -> Optional[Dict[str, int]]:
    band = _target_word_band_bounds(target_length)
    if band is None:
        return None
    lower, upper, tolerance = band
    return {
        "lower": int(lower),
        "upper": int(upper),
        "tolerance": int(tolerance),
    }


def _explicit_target_word_band_status(
    *,
    summary_text: str,
    target_length: Optional[int],
    summary_meta: Optional[Dict[str, Any]] = None,
) -> Optional[Dict[str, Any]]:
    band = _summary_target_band_detail(target_length)
    if band is None:
        return None
    _ = summary_meta if isinstance(summary_meta, dict) else {}
    final_split_word_count = int(len((summary_text or "").split()))
    final_word_count = int(_count_words(summary_text or ""))
    return {
        "lower": int(band["lower"]),
        "upper": int(band["upper"]),
        "tolerance": int(band["tolerance"]),
        "target_band": dict(band),
        "final_split_word_count": int(final_split_word_count),
        "final_word_count": int(final_word_count),
        "in_band": bool(
            int(band["lower"]) <= final_word_count <= int(band["upper"])
        ),
    }


def _explicit_target_word_band_failure_detail(
    *,
    summary_text: str,
    target_length: Optional[int],
    summary_meta: Optional[Dict[str, Any]] = None,
    missing_requirements: Optional[List[str]] = None,
    detail_message: str = "Unable to satisfy explicit target word-count contract after bounded retries.",
) -> Optional[Dict[str, Any]]:
    status = _explicit_target_word_band_status(
        summary_text=summary_text,
        target_length=target_length,
        summary_meta=summary_meta,
    )
    if status is None or bool(status.get("in_band")):
        return None

    meta_missing = (
        list(summary_meta.get("contract_missing_requirements") or [])
        if isinstance(summary_meta, dict)
        else []
    )
    band_requirement = (
        f"Final word-count band violation: expected {int(status['lower'])}-{int(status['upper'])}, "
        f"got split={int(status['final_split_word_count'])}, stripped={int(status['final_word_count'])}."
    )
    merged_missing = _strip_quality_validator_items(list(
        dict.fromkeys(
            [
                str(item).strip()
                for item in (
                    list(missing_requirements or [])
                    + list(meta_missing or [])
                    + [band_requirement]
                )
                if str(item).strip()
            ]
        )
    ))
    return {
        "detail": str(detail_message or "").strip()
        or "Unable to satisfy explicit target word-count contract after bounded retries.",
        "failure_code": "SUMMARY_CONTRACT_FAILED",
        "target_length": int(target_length or 0),
        "actual_word_count": int(status["final_word_count"]),
        "target_band": dict(status["target_band"]),
        "missing_requirements": merged_missing[:12],
    }


def _append_short_visible_band_requirement(
    *,
    missing_requirements: Optional[List[str]],
    summary_text: str,
    target_length: Optional[int],
) -> List[str]:
    items = [
        str(item).strip() for item in (missing_requirements or []) if str(item).strip()
    ]
    if not target_length or not _is_short_mid_precision_target(target_length):
        return items

    band = _target_word_band_bounds(target_length)
    if band is None:
        return items

    lower, upper, _tolerance = band
    final_split_word_count = len((summary_text or "").split())
    final_word_count = _count_words(summary_text or "")
    # Use canonical stripped count as single source of truth — punctuation-heavy
    # financial text (→, $, %, —) creates a natural 15-30 word divergence between
    # split() and _count_words(), making a dual-counter AND gate impossible to satisfy.
    in_band = lower <= final_word_count <= upper

    def _is_word_band_requirement(item: Any) -> bool:
        lowered = str(item or "").lower()
        return (
            "word-count band violation" in lowered
            or "under word target" in lowered
            or "over word target" in lowered
        )

    non_band_items = [item for item in items if not _is_word_band_requirement(item)]
    if in_band:
        return non_band_items

    band_requirement = (
        f"Final word-count band violation: expected {int(lower)}-{int(upper)}, "
        f"got split={int(final_split_word_count)}, stripped={int(final_word_count)}."
    )
    return list(dict.fromkeys(non_band_items + [band_requirement]))


def _raise_if_explicit_target_response_out_of_band(
    *,
    filing_id: Any,
    payload: Dict[str, Any],
    target_length: Optional[int],
    explicit_target_requested: bool,
    summary_request_id: Optional[str] = None,
    missing_requirements: Optional[List[str]] = None,
    detail_message: str = "Unable to satisfy explicit target word-count contract after bounded retries.",
) -> None:
    if not explicit_target_requested or not target_length:
        return
    summary_text = str(payload.get("summary") or "").strip()
    if not summary_text:
        return
    payload_summary_meta = payload.get("summary_meta")
    summary_meta = (
        payload_summary_meta if isinstance(payload_summary_meta, dict) else {}
    )
    status = _explicit_target_word_band_status(
        summary_text=summary_text,
        target_length=target_length,
        summary_meta=summary_meta,
    )
    if status is not None:
        summary_meta["final_split_word_count"] = int(status["final_split_word_count"])
        summary_meta["final_word_count"] = int(status["final_word_count"])
        payload["summary_meta"] = summary_meta
    detail = _explicit_target_word_band_failure_detail(
        summary_text=summary_text,
        target_length=target_length,
        summary_meta=summary_meta,
        missing_requirements=missing_requirements,
        detail_message=detail_message,
    )
    if detail is None:
        return

    def _is_word_band_requirement(item: Any) -> bool:
        lowered = str(item or "").lower()
        return (
            "word-count band violation" in lowered
            or "under word target" in lowered
            or "over word target" in lowered
        )

    meta_missing = list(summary_meta.get("contract_missing_requirements") or [])
    caller_word_band_issue = any(
        _is_word_band_requirement(item) for item in list(missing_requirements or [])
    )
    non_band_requirements = [
        item
        for item in list(dict.fromkeys(meta_missing + list(missing_requirements or [])))
        if not _is_word_band_requirement(item)
    ]
    rewrite_attempted = bool(
        int(summary_meta.get("llm_rewrite_calls") or 0) > 0
        or int(summary_meta.get("retry_count") or 0) > 0
        or int(summary_meta.get("contract_recovery_generation_calls") or 0) > 0
        or bool(summary_meta.get("contract_recovery_used"))
    )
    band_underflow = bool(
        status is not None
        and int(status.get("final_split_word_count") or 0)
        < int(status.get("lower") or 0)
        and int(status.get("final_word_count") or 0) < int(status.get("lower") or 0)
    )
    quote_requirement_present = any(
        "management discussion & analysis must include at least one verified direct quote"
        in str(item or "").lower()
        for item in non_band_requirements
    )
    if (
        _is_long_form_target(target_length)
        and quote_requirement_present
        and len(non_band_requirements) == 1
        and not caller_word_band_issue
        and not rewrite_attempted
        and band_underflow
    ):
        payload["contract_warnings"] = list(
            dict.fromkeys(
                list(payload.get("contract_warnings") or [])
                + list(detail.get("missing_requirements") or [])
            )
        )
        summary_meta["contract_missing_requirements"] = list(
            dict.fromkeys(non_band_requirements)
        )
        payload["summary_meta"] = summary_meta
        return
    summary_meta["contract_missing_requirements"] = list(
        detail.get("missing_requirements") or []
    )
    _record_summary_422_observability(
        filing_id=filing_id,
        detail=detail,
        summary_request_id=summary_request_id,
        fallback_target_length=int(target_length or 0),
    )
    raise HTTPException(status_code=422, detail=detail)


def _record_summary_422_observability(
    *,
    filing_id: Any,
    detail: Any,
    summary_request_id: Optional[str] = None,
    fallback_target_length: Optional[int] = None,
) -> None:
    """Persist progress error detail and emit structured logging for summary 422s."""
    payload: Dict[str, Any]
    if isinstance(detail, dict):
        payload = dict(detail)
    else:
        payload = {"detail": str(detail)}

    failure_code = (
        str(payload.get("failure_code") or "SUMMARY_422").strip() or "SUMMARY_422"
    )
    target_length = payload.get("target_length", fallback_target_length)
    try:
        target_length_int = (
            int(target_length) if target_length not in (None, "", 0, "0") else None
        )
    except (TypeError, ValueError):
        target_length_int = None

    actual_word_count = payload.get("actual_word_count")
    try:
        actual_word_count_int = (
            int(actual_word_count)
            if actual_word_count not in (None, "", "null")
            else None
        )
    except (TypeError, ValueError):
        actual_word_count_int = None

    missing_requirements = (
        payload.get("missing_requirements")
        if isinstance(payload.get("missing_requirements"), list)
        else None
    )
    diagnostic_missing_requirements = (
        payload.get("diagnostic_missing_requirements")
        if isinstance(payload.get("diagnostic_missing_requirements"), list)
        else None
    )

    progress_message = str(payload.get("detail") or "Summary request failed.").strip()
    try:
        set_summary_progress(
            str(filing_id),
            status=progress_message[:160],
            stage_percent=0,
            error=True,
            last_failure_code=failure_code,
            last_error_message=progress_message,
            last_error_details=payload,
        )
    except Exception as progress_exc:  # noqa: BLE001
        logger.debug(
            "Unable to persist summary progress error for %s: %s",
            filing_id,
            progress_exc,
        )

    logger.warning(
        "Summary 422 failure: filing_id=%s request_id=%s failure_code=%s target_length=%s actual_word_count=%s revision=%s output_format=%s contract_scope=%s target_band=%s missing_requirements=%s diagnostic_missing_requirements=%s",
        filing_id,
        summary_request_id,
        failure_code,
        target_length_int,
        actual_word_count_int,
        str(os.getenv("K_REVISION") or "").strip() or None,
        payload.get("output_format"),
        payload.get("contract_scope"),
        payload.get("target_band"),
        missing_requirements[:8] if missing_requirements else None,
        diagnostic_missing_requirements[:8]
        if diagnostic_missing_requirements
        else None,
    )


def _estimate_contract_quote_pool_size(
    filing_language_snippets: str, *, target_quotes: int
) -> int:
    snippets = str(filing_language_snippets or "")
    if not snippets.strip():
        return 0

    def _dedupe(values: List[str]) -> List[str]:
        out: List[str] = []
        seen: Set[str] = set()
        for item in values:
            normalized = re.sub(r"\s+", " ", str(item or "").strip().lower()).strip()
            if not normalized or normalized in seen:
                continue
            seen.add(normalized)
            out.append(" ".join(str(item or "").split()).strip())
        return out

    quote_pool = _dedupe(_extract_quotes_from_filing_snippets(snippets))
    if len(quote_pool) >= int(target_quotes):
        return len(quote_pool)

    management_patterns = [
        r"(?:we|the company|management)\s+(?:believe|expect|anticipate|continue|remain|plan|intend)[^.]{10,120}\.",
        r"(?:our|the)\s+(?:strategy|focus|priority|goal|objective)[^.]{10,120}\.",
    ]
    fallback_quotes: List[str] = []
    for pattern in management_patterns:
        for match in re.finditer(pattern, snippets, re.IGNORECASE):
            candidate = str(match.group(0) or "").strip().rstrip(".")
            if 10 <= len(candidate.split()) <= 30:
                fallback_quotes.append(candidate)
        if len(quote_pool) + len(fallback_quotes) >= int(target_quotes):
            break
    quote_pool = _dedupe(quote_pool + fallback_quotes)
    return len(quote_pool)


def _build_precision_section_balance_guidance(
    *,
    summary_text: str,
    target_length: Optional[int],
    include_health_rating: bool,
    missing_requirements: Optional[List[str]],
) -> str:
    if not target_length:
        return ""
    issue_flags = _parse_summary_contract_missing_requirements(missing_requirements)
    if not issue_flags.get("section_balance_issue"):
        return ""

    budgets = _calculate_section_word_budgets(
        int(target_length), include_health_rating=include_health_rating
    )
    if not budgets:
        return ""
    counts = _collect_section_body_word_counts(
        summary_text or "", include_health_rating=include_health_rating
    )
    lines: List[str] = []
    preferred_under = set(issue_flags.get("section_balance_underweight_titles") or [])
    preferred_over = set(issue_flags.get("section_balance_overweight_titles") or [])
    narrative_titles = [
        title
        for title in _SUMMARY_NARRATIVE_REPETITION_SECTIONS
        if include_health_rating or title != "Financial Health Rating"
    ]
    under_candidates: List[Tuple[int, str, int, int]] = []
    over_candidates: List[Tuple[int, str, int, int]] = []
    for title in narrative_titles:
        expected = int(budgets.get(title, 0) or 0)
        observed = int(counts.get(title, 0) or 0)
        if expected <= 0:
            continue
        delta = observed - expected
        if delta < 0:
            under_candidates.append((abs(delta), title, observed, expected))
        elif delta > 0:
            over_candidates.append((delta, title, observed, expected))

    under_candidates.sort(
        key=lambda item: (
            item[1] not in preferred_under,
            -item[0],
            _summary_repetition_section_priority(item[1]),
        )
    )
    over_candidates.sort(
        key=lambda item: (
            item[1] not in preferred_over,
            -item[0],
            _summary_repetition_section_priority(item[1]),
        )
    )

    for deficit, title, observed, expected in under_candidates[:4]:
        lines.append(
            f"- EXPAND '{title}' by about {deficit}-{deficit + 12} words (current {observed}, target ~{expected})."
        )
    for excess, title, observed, expected in over_candidates[:3]:
        lines.append(
            f"- TIGHTEN '{title}' by about {max(5, excess - 8)}-{excess} words (current {observed}, target ~{expected})."
        )
    if not lines:
        return ""
    return (
        "\nSECTION BALANCE PRIORITY:\n"
        + "\n".join(lines)
        + "\nKeep all quotes, the Health→Executive bridge, Key Metrics format, and Closing triggers intact while rebalancing."
    )


def _sub_outside_direct_quotes(
    text: str,
    pattern: re.Pattern[str],
    repl,
    *,
    count: int = 0,
) -> Tuple[str, int]:
    """Apply regex replacement only outside direct-quote spans."""
    if not text:
        return text, 0

    quote_span_re = re.compile(r"[“\"][^“”\"\n]{0,260}[”\"]")
    out_parts: List[str] = []
    last = 0
    total_replacements = 0
    remaining = int(count) if count else 0

    def _apply(segment: str) -> Tuple[str, int]:
        nonlocal remaining
        if not segment:
            return segment, 0
        if count and remaining <= 0:
            return segment, 0
        seg_count = remaining if count else 0
        new_segment, made = pattern.subn(repl, segment, count=seg_count)
        if count:
            remaining -= int(made)
        return new_segment, int(made)

    for quote_match in quote_span_re.finditer(text):
        segment = text[last : quote_match.start()]
        new_segment, made = _apply(segment)
        out_parts.append(new_segment)
        out_parts.append(quote_match.group(0))
        total_replacements += int(made)
        last = quote_match.end()

    tail = text[last:]
    new_tail, made_tail = _apply(tail)
    out_parts.append(new_tail)
    total_replacements += int(made_tail)
    return "".join(out_parts), total_replacements


def _replace_literal_outside_direct_quotes(
    text: str,
    literal: str,
    replacement: str,
    *,
    count: int = 1,
) -> Tuple[str, int]:
    if not literal:
        return text, 0
    return _sub_outside_direct_quotes(
        text,
        re.compile(re.escape(literal)),
        replacement,
        count=count,
    )


def _summary_repetition_section_priority(title: str) -> int:
    order = {
        "Financial Performance": 0,
        "Management Discussion & Analysis": 1,
        "Financial Health Rating": 2,
        "Executive Summary": 3,
        "Risk Factors": 4,
        "Closing Takeaway": 5,
    }
    return int(order.get(str(title or "").strip(), 99))


def _sorted_repetition_sections(section_titles: List[str]) -> List[str]:
    input_order = {title: idx for idx, title in enumerate(section_titles or [])}
    return sorted(
        [
            str(title or "").strip()
            for title in section_titles
            if str(title or "").strip()
        ],
        key=lambda t: (
            _summary_repetition_section_priority(t),
            input_order.get(t, 999),
        ),
    )


def _normalize_closing_prose_spacing(body: str) -> str:
    out = str(body or "")
    out = re.sub(r"\s+([,.;:!?])", r"\1", out)
    out = re.sub(r"\(\s+", "(", out)
    out = re.sub(r"\s+\)", ")", out)
    out = re.sub(r"[ \t]{2,}", " ", out)
    out = re.sub(r"\n{3,}", "\n\n", out)
    out = re.sub(r"\s+\.", ".", out)
    return out.strip()


def _remove_low_signal_closing_parentheticals(body: str) -> Tuple[str, int]:
    if not body:
        return body, 0

    parenthetical_filler_re = re.compile(
        r"\((?:on a forward basis|from a portfolio perspective|as things stand|in this environment|at this stage)\)",
        re.IGNORECASE,
    )
    legacy_parenthetical_filler_re = re.compile(
        r"\((?:key swing factor|primary swing factor|near term factors|in practical terms|fundamental catalyst|structural driver|"
        r"operating backdrop|valuation context|execution priority|capital intensity backdrop|on a forward basis|relative to the cycle|"
        r"across the enterprise|from a risk standpoint|on a relative basis|under current conditions|given the trajectory|within this framework)\)",
        re.IGNORECASE,
    )
    parenthetical_chunk_re = re.compile(r"\(([^)\n]{1,60})\)")

    removed = 0

    def _drop_known_fillers(match: re.Match[str]) -> str:
        nonlocal removed
        removed += 1
        return ""

    out, _ = _sub_outside_direct_quotes(
        body, parenthetical_filler_re, _drop_known_fillers, count=0
    )
    out, _ = _sub_outside_direct_quotes(
        out, legacy_parenthetical_filler_re, _drop_known_fillers, count=0
    )

    def _maybe_drop_chunk(match: re.Match[str]) -> str:
        nonlocal removed
        chunk = str(match.group(1) or "")
        chunk_norm = " ".join(chunk.lower().split()).strip()
        if not chunk_norm:
            removed += 1
            return ""
        if re.search(
            r"\d|%|\$|buy|hold|sell|if|unless|q[1-4]|fy\d{2}",
            chunk_norm,
            re.IGNORECASE,
        ):
            return match.group(0)
        if len(chunk_norm.split()) <= 5:
            removed += 1
            return ""
        return match.group(0)

    out, _ = _sub_outside_direct_quotes(
        out, parenthetical_chunk_re, _maybe_drop_chunk, count=0
    )
    return _normalize_closing_prose_spacing(out), int(removed)


def _cap_closing_takeaway_sentences_preserve_triggers(
    body: str,
    *,
    max_sentences: Optional[int] = None,
    budget_words: Optional[int] = None,
) -> Tuple[str, int]:
    """Cap closing sentences while preserving stance/trigger structure."""
    if not body:
        return body, 0
    if max_sentences is None:
        max_sentences = _closing_sentence_cap_for_budget(budget_words)
    sentences = [
        s.strip()
        for s in re.split(r"(?<=[.!?])\s+", str(body or "").strip())
        if s.strip()
    ]
    max_allowed = max(1, int(max_sentences))
    if len(sentences) <= max_allowed:
        return body, 0

    stance_re = re.compile(r"\b(buy|hold|sell|neutral)\b", re.IGNORECASE)
    trigger_indexes = {
        idx
        for idx, sentence in enumerate(sentences)
        if _is_closing_trigger_sentence_for_balance_trim(sentence)
    }
    first_stance_idx: Optional[int] = None
    for idx, sentence in enumerate(sentences):
        if stance_re.search(sentence):
            first_stance_idx = idx
            break

    protected: Set[int] = {0}
    protected.update(trigger_indexes)
    if first_stance_idx is not None:
        protected.add(int(first_stance_idx))

    keep = [True] * len(sentences)
    current = len(sentences)

    # First remove excess non-protected sentences from the tail.
    for idx in range(len(sentences) - 1, -1, -1):
        if current <= max_allowed:
            break
        if idx in protected:
            continue
        keep[idx] = False
        current -= 1

    # If still too long (rare: many protected sentences), keep the first sentence and
    # up to two trigger sentences, then trim remaining protected sentences from the tail.
    if current > max_allowed:
        kept_trigger_count = sum(1 for idx in trigger_indexes if keep[idx])
        for idx in range(len(sentences) - 1, -1, -1):
            if current <= max_allowed:
                break
            if not keep[idx]:
                continue
            if idx == 0:
                continue
            if idx in trigger_indexes and kept_trigger_count <= 2:
                continue
            if idx == first_stance_idx and idx != 0:
                continue
            if idx in trigger_indexes:
                kept_trigger_count -= 1
            keep[idx] = False
            current -= 1

    rebuilt = " ".join(
        sentences[idx] for idx in range(len(sentences)) if keep[idx]
    ).strip()
    rebuilt = _normalize_closing_prose_spacing(rebuilt)
    if rebuilt and not rebuilt.endswith((".", "!", "?")):
        rebuilt += "."
    removed = max(0, len(sentences) - sum(1 for flag in keep if flag))
    return rebuilt or body, int(removed)


def _replace_repeated_figure_outside_quotes(
    body: str,
    *,
    normalized_figure: str,
    replacement: str,
) -> Tuple[str, int]:
    if not body or not normalized_figure:
        return body, 0

    replaced = 0

    def _figure_repl(match: re.Match[str]) -> str:
        nonlocal replaced
        raw = str(match.group(0) or "")
        if _normalize_repeated_figure_token(raw) != normalized_figure:
            return raw
        replaced += 1
        return replacement

    out, _ = _sub_outside_direct_quotes(body, _SUMMARY_REPEATED_FIGURE_RE, _figure_repl)
    return out, int(replaced)


def _theme_context_reference(theme_name: str) -> str:
    replacements = {
        "cash conversion": "cash realization",
        "free cash flow": "cash generation",
        "margin pressure": "profitability pressure",
        "reinvestment": "investment cadence",
        "balance sheet flexibility": "financial flexibility",
        "working capital": "short-term operating timing",
        "below the line": "non-operating support",
        "earnings quality": "profit quality",
    }
    return replacements.get(theme_name, "this dynamic")


def _replace_theme_once_outside_quotes(
    body: str,
    *,
    theme_name: str,
) -> Tuple[str, int]:
    pattern = _SUMMARY_THEME_PATTERNS.get(theme_name)
    if not body or pattern is None:
        return body, 0

    replacement = _theme_context_reference(theme_name)
    out, made = _sub_outside_direct_quotes(body, pattern, replacement, count=1)
    return out, int(made)


def _scrub_executive_summary_numeric_density(
    summary_text: str,
    *,
    target_length: Optional[int],
    quality_profile: Optional[SummaryFlowQualityProfile] = None,
) -> Tuple[str, int]:
    text = (summary_text or "").strip()
    if not text:
        return summary_text, 0

    caps = _numbers_discipline_caps(
        target_length,
        closing_numeric_cap_override=(
            quality_profile.closing_numeric_anchor_cap if quality_profile else None
        ),
    )
    max_exec = int(caps.get("Executive Summary", 4))
    exec_body = _extract_markdown_section_body(text, "Executive Summary")
    if not exec_body:
        return summary_text, 0

    exec_count = _count_numeric_tokens(exec_body)
    if exec_count <= max_exec:
        return summary_text, 0

    numeric_re = re.compile(
        r"(?:[$€£]\s*)?\b\d+(?:\.\d+)?\s*(?:%|x|pp|b|bn|m|mm|million|billion)?\b",
        re.IGNORECASE,
    )
    sentences = _split_sentences(exec_body)
    if not sentences:
        return summary_text, 0

    sentence_num_counts = [len(numeric_re.findall(sentence)) for sentence in sentences]
    sentence_priority: List[Tuple[int, int]] = []
    for idx, sentence in enumerate(sentences):
        score = 0
        if idx == 0:
            score += 3
        if re.search(r"[“\"]", sentence):
            score += 3
        if re.search(
            r"\b(management|CEO|CFO|company)\b.{0,40}\b(said|noted|stated|expects?|guides?|plans?|priorit(?:y|ies|ize|izing))\b",
            sentence,
            re.IGNORECASE,
        ):
            score += 4
        if sentence_num_counts[idx] == 0:
            score += 2
        sentence_priority.append((score, idx))

    priority_indexes: List[int] = []
    for _score, idx in sorted(sentence_priority, key=lambda item: (-item[0], item[1])):
        if idx not in priority_indexes:
            priority_indexes.append(idx)
        if len(priority_indexes) >= 2:
            break

    kept_indexes: List[int] = []
    numeric_total = 0
    for idx in sorted(priority_indexes):
        count = int(sentence_num_counts[idx])
        if count and numeric_total + count > max_exec:
            continue
        kept_indexes.append(idx)
        numeric_total += count

    for idx, sentence in enumerate(sentences):
        if idx in kept_indexes:
            continue
        count = int(sentence_num_counts[idx])
        if count == 0:
            kept_indexes.append(idx)
            continue
        if numeric_total + count <= max_exec:
            kept_indexes.append(idx)
            numeric_total += count

    kept_indexes = sorted(set(kept_indexes))
    cleaned_exec = " ".join(
        sentences[idx].strip()
        for idx in kept_indexes
        if 0 <= idx < len(sentences) and sentences[idx].strip()
    )
    cleaned_exec = _normalize_closing_prose_spacing(cleaned_exec)
    if _count_numeric_tokens(cleaned_exec) >= exec_count:
        return summary_text, 0
    out = _replace_markdown_section_body(text, "Executive Summary", cleaned_exec)
    return out, max(0, len(sentences) - len(kept_indexes))


def _scrub_section_numeric_density(
    summary_text: str,
    *,
    section_title: str,
    target_length: Optional[int],
    quality_profile: Optional[SummaryFlowQualityProfile] = None,
) -> Tuple[str, int]:
    """Reduce numeric-token density in a narrative section without touching quotes."""
    text = (summary_text or "").strip()
    if not text or not section_title:
        return summary_text, 0

    caps = _numbers_discipline_caps(
        target_length,
        closing_numeric_cap_override=(
            quality_profile.closing_numeric_anchor_cap if quality_profile else None
        ),
    )
    max_allowed = int(caps.get(section_title, 0) or 0)
    if max_allowed <= 0:
        return summary_text, 0

    body = _extract_markdown_section_body(text, section_title)
    if not body:
        return summary_text, 0
    current_count = _count_numeric_tokens(body)
    if current_count <= max_allowed:
        return summary_text, 0

    # Instead of replacing individual numeric tokens with filler phrases
    # (which produces garbled prose), drop entire sentences that contain
    # excess numbers.  This is cleaner — the word-count trimmer handles
    # any resulting length changes.
    numeric_re = re.compile(r"\b[\w$€£]*\d[\w%/.\-]*\b")
    sentences = _split_sentences(body)
    if not sentences:
        return summary_text, 0

    # Tag each sentence with its numeric token count
    sentence_num_counts = [len(numeric_re.findall(s)) for s in sentences]
    running_total = 0
    kept: list[str] = []
    dropped = 0
    for sent, num_count in zip(sentences, sentence_num_counts):
        if running_total + num_count <= max_allowed:
            kept.append(sent)
            running_total += num_count
        elif running_total < max_allowed and num_count > 0:
            # This sentence would push us over — drop it entirely
            dropped += 1
        else:
            if num_count == 0:
                # Sentence has no numbers — always keep
                kept.append(sent)
            else:
                dropped += 1

    if dropped == 0:
        return summary_text, 0
    cleaned_body = " ".join(kept)
    cleaned_body = _normalize_closing_prose_spacing(cleaned_body)
    if _count_numeric_tokens(cleaned_body) >= current_count:
        return summary_text, 0
    out = _replace_markdown_section_body(text, section_title, cleaned_body)
    return out, dropped


def _dedupe_cross_section_numbers_in_summary(
    summary_text: str,
    *,
    max_sections_per_figure: int,
) -> Tuple[str, int]:
    text = (summary_text or "").strip()
    if not text:
        return summary_text, 0
    max_allowed = max(1, int(max_sections_per_figure))
    replaced_total = 0

    figure_section_map: Dict[str, set] = {}
    for section_title in _SUMMARY_NARRATIVE_REPETITION_SECTIONS:
        body = _extract_markdown_section_body(text, section_title)
        if not body:
            continue
        for fig_match in _SUMMARY_REPEATED_FIGURE_RE.finditer(
            _strip_direct_quote_spans(body)
        ):
            norm = _normalize_repeated_figure_token(fig_match.group(0))
            if not norm:
                continue
            figure_section_map.setdefault(norm, set()).add(section_title)

    for norm_figure, sections in figure_section_map.items():
        section_list = _sorted_repetition_sections(list(sections))
        if len(section_list) <= max_allowed:
            continue
        keep_sections = set(section_list[:max_allowed])
        excess_sections = [s for s in section_list if s not in keep_sections]
        for section_title in excess_sections:
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue
            replacement = ""
            new_body, made = _replace_repeated_figure_outside_quotes(
                body,
                normalized_figure=norm_figure,
                replacement=replacement,
            )
            if made and new_body != body:
                text = _replace_markdown_section_body(text, section_title, new_body)
                replaced_total += int(made)
    return text, int(replaced_total)


def _dedupe_cross_section_themes_in_summary(
    summary_text: str,
    *,
    max_sections_per_theme: int,
) -> Tuple[str, int]:
    text = (summary_text or "").strip()
    if not text:
        return summary_text, 0
    max_allowed = max(1, int(max_sections_per_theme))
    replaced_total = 0

    theme_section_map: Dict[str, set] = {}
    for section_title in _SUMMARY_NARRATIVE_REPETITION_SECTIONS:
        body = _extract_markdown_section_body(text, section_title)
        if not body:
            continue
        unquoted_body = _strip_direct_quote_spans(body)
        for theme_name, pattern in _SUMMARY_THEME_PATTERNS.items():
            if pattern.search(unquoted_body):
                theme_section_map.setdefault(theme_name, set()).add(section_title)

    for theme_name, sections in theme_section_map.items():
        section_list = _sorted_repetition_sections(list(sections))
        if len(section_list) <= max_allowed:
            continue
        keep_sections = set(section_list[:max_allowed])
        excess_sections = [s for s in section_list if s not in keep_sections]
        for section_title in excess_sections:
            body = _extract_markdown_section_body(text, section_title)
            if not body:
                continue
            _theme_pattern = _SUMMARY_THEME_PATTERNS.get(theme_name)
            if _theme_pattern is None:
                continue
            new_body, made = _sub_outside_direct_quotes(
                body,
                _theme_pattern,
                _theme_context_reference(theme_name),
                count=0,
            )
            if made and new_body != body:
                text = _replace_markdown_section_body(text, section_title, new_body)
                replaced_total += int(made)
    return text, int(replaced_total)


def _dedupe_cross_section_question_framing_in_summary(
    summary_text: str,
) -> Tuple[str, int]:
    """Keep thesis-question framing once, then force later sections to answer directly."""
    text = (summary_text or "").strip()
    if not text:
        return summary_text, 0

    removed_total = 0
    seen_question_frame = False
    for section_title in _SUMMARY_NARRATIVE_REPETITION_SECTIONS:
        body = _extract_markdown_section_body(text, section_title)
        if not body:
            continue

        sentences = [
            s.strip() for s in re.split(r"(?<=[.!?])\s+", body.strip()) if s.strip()
        ]
        if not sentences:
            continue

        kept: List[str] = []
        local_removed = 0
        for sentence in sentences:
            is_question_frame = any(
                pattern.search(sentence)
                for pattern in _SUMMARY_QUESTION_FRAMING_PATTERNS
            )
            if not is_question_frame:
                kept.append(sentence)
                continue
            if not seen_question_frame:
                kept.append(sentence)
                seen_question_frame = True
                continue
            local_removed += 1

        if local_removed <= 0 or not kept:
            continue
        rebuilt_body = " ".join(kept).strip()
        rebuilt_body = _normalize_closing_prose_spacing(rebuilt_body)
        if rebuilt_body and not rebuilt_body.endswith((".", "!", "?")):
            rebuilt_body += "."
        text = _replace_markdown_section_body(text, section_title, rebuilt_body)
        removed_total += int(local_removed)

    return text, int(removed_total)


_LWR_TRANSITION_BANK: Tuple[str, ...] = (
    "Additionally, ",
    "Moreover, ",
    "In particular, ",
    "Notably, ",
    "Furthermore, ",
    "Separately, ",
    "Meanwhile, ",
    "On top of that, ",
    "Beyond that, ",
)


def _repair_section_leading_word_repetition(
    body: str,
    *,
    max_same_opening: int,
) -> Tuple[str, int]:
    if not body:
        return body, 0

    sentences = [
        s.strip()
        for s in re.split(r"(?<=[.!?])\s+", str(body or "").strip())
        if s.strip()
    ]
    if len(sentences) < 5:
        return body, 0

    stopwords = {
        "the",
        "a",
        "an",
        "and",
        "or",
        "but",
        "so",
        "to",
        "of",
        "in",
        "on",
        "for",
        "with",
        "as",
        "at",
        "by",
        "from",
        "this",
        "that",
        "these",
        "those",
    }
    max_allowed = max(1, int(max_same_opening))
    prefixes = list(_LWR_TRANSITION_BANK)

    def _is_quoted_sentence(sentence: str) -> bool:
        return '"' in sentence or "“" in sentence or "”" in sentence

    def _strip_known_prefix(sentence: str) -> Tuple[str, bool]:
        for pref in prefixes:
            if sentence.lower().startswith(pref.lower()):
                return sentence[len(pref) :].lstrip(), True
        return sentence, False

    def _leading_word(sentence: str) -> str:
        stripped, _ = _strip_known_prefix(sentence)
        if not stripped:
            return ""
        first = stripped.split()[0].lower().rstrip(".,;:")
        if first.startswith("#") or first in stopwords:
            return ""
        return first

    lwr_counts: Dict[str, List[int]] = {}
    for idx, sentence in enumerate(sentences):
        if len(sentence.split()) < 6:
            continue
        word = _leading_word(sentence)
        if word:
            lwr_counts.setdefault(word, []).append(idx)

    rewrites = 0
    prefix_idx = 0
    for _word, indexes in lwr_counts.items():
        if len(indexes) <= max_allowed:
            continue
        kept = 0
        for sent_idx in indexes:
            if kept < max_allowed:
                kept += 1
                continue
            original = sentences[sent_idx]
            if not original or _is_quoted_sentence(original):
                continue
            stripped, already_prefixed = _strip_known_prefix(original)
            if already_prefixed:
                # Avoid stacking prefixes; leave as-is and count as effectively rewritten.
                continue
            if not stripped:
                continue
            while prefix_idx < len(prefixes):
                prefix = prefixes[prefix_idx]
                prefix_idx += 1
                if not original.lower().startswith(prefix.lower()):
                    break
            else:
                break
            if len(stripped) == 1:
                rebuilt = prefix + stripped.lower()
            else:
                rebuilt = prefix + stripped[0].lower() + stripped[1:]
            sentences[sent_idx] = rebuilt
            rewrites += 1

    if rewrites <= 0:
        return body, 0

    rebuilt_body = " ".join(sentences).strip()
    rebuilt_body = _normalize_closing_prose_spacing(rebuilt_body)
    if rebuilt_body and not rebuilt_body.endswith((".", "!", "?")):
        rebuilt_body += "."
    return rebuilt_body or body, int(rewrites)


def _repair_leading_word_repetition_in_summary(
    summary_text: str,
    *,
    max_same_opening: int,
    target_sections: Optional[List[str]] = None,
) -> Tuple[str, Dict[str, Any]]:
    text = (summary_text or "").strip()
    info: Dict[str, Any] = {"changed": False, "rewrites": 0, "sections": []}
    if not text:
        return summary_text, info

    allowed_sections = (
        [s for s in (target_sections or []) if s]
        if target_sections
        else list(_SUMMARY_NARRATIVE_REPETITION_SECTIONS)
    )
    for section_title in allowed_sections:
        if section_title == "Key Metrics":
            continue
        body = _extract_markdown_section_body(text, section_title)
        if not body:
            continue
        new_body, rewrites = _repair_section_leading_word_repetition(
            body,
            max_same_opening=max_same_opening,
        )
        if rewrites > 0 and new_body != body:
            text = _replace_markdown_section_body(text, section_title, new_body)
            info["changed"] = True
            info["rewrites"] = int(info.get("rewrites", 0) or 0) + int(rewrites)
            info["sections"].append(section_title)
    return text, info


def _apply_editorial_contract_repairs(
    summary_text: str,
    *,
    target_length: Optional[int],
    include_health_rating: bool,
    quality_profile: SummaryFlowQualityProfile,
    missing_requirements: Optional[List[str]] = None,
    issue_flags: Optional[Dict[str, Any]] = None,
    generation_stats: Optional[Dict[str, Any]] = None,
) -> Tuple[str, Dict[str, Any]]:
    text = (summary_text or "").strip()
    info: Dict[str, Any] = {
        "changed": False,
        "actions": [],
        "closing_parenthetical_removals": 0,
        "exec_numeric_scrub_replacements": 0,
        "perf_numeric_scrub_replacements": 0,
        "mdna_numeric_scrub_replacements": 0,
        "generic_numeric_scrub_replacements": 0,
        "number_dedupe_replacements": 0,
        "theme_dedupe_replacements": 0,
        "question_framing_rewrites": 0,
        "leading_word_repetition_rewrites": 0,
        "leading_word_repetition_fix_sections": [],
    }
    if not text:
        return summary_text, info

    flags = issue_flags or _parse_summary_contract_missing_requirements(
        missing_requirements
    )
    if not flags.get("needs_editorial_deterministic_repair"):
        return summary_text, info

    if flags.get("closing_parenthetical_issue"):
        closing_body = _extract_markdown_section_body(text, "Closing Takeaway")
        if closing_body:
            cleaned_closing, removed = _remove_low_signal_closing_parentheticals(
                closing_body
            )
            if removed and cleaned_closing != closing_body:
                text = _replace_markdown_section_body(
                    text, "Closing Takeaway", cleaned_closing
                )
                info["changed"] = True
                info["closing_parenthetical_removals"] = int(removed)
                info["actions"].append("closing_parenthetical_cleanup")

    if flags.get("number_repetition_issue"):
        updated, replaced_count = _dedupe_cross_section_numbers_in_summary(
            text,
            max_sections_per_figure=quality_profile.max_sections_per_repeated_number,
        )
        if replaced_count and updated != text:
            text = updated
            info["changed"] = True
            info["number_dedupe_replacements"] = int(replaced_count)
            info["actions"].append("cross_section_number_dedupe")

    if flags.get("theme_repetition_issue"):
        updated, replaced_count = _dedupe_cross_section_themes_in_summary(
            text,
            max_sections_per_theme=quality_profile.max_sections_per_theme,
        )
        if replaced_count and updated != text:
            text = updated
            info["changed"] = True
            info["theme_dedupe_replacements"] = int(replaced_count)
            info["actions"].append("cross_section_theme_dedupe")

    if flags.get("question_framing_repetition_issue"):
        updated, replaced_count = _dedupe_cross_section_question_framing_in_summary(
            text
        )
        if replaced_count and updated != text:
            text = updated
            info["changed"] = True
            info["question_framing_rewrites"] = int(replaced_count)
            info["actions"].append("cross_section_question_framing_dedupe")

    if flags.get("leading_word_repetition_issue"):
        updated, lwr_info = _repair_leading_word_repetition_in_summary(
            text,
            max_same_opening=max(
                1, int(getattr(quality_profile, "max_same_opening", 2) or 2)
            ),
            target_sections=list(flags.get("leading_word_repetition_sections") or []),
        )
        if lwr_info.get("changed") and updated != text:
            text = updated
            info["changed"] = True
            info["leading_word_repetition_rewrites"] = int(
                lwr_info.get("rewrites", 0) or 0
            )
            info["leading_word_repetition_fix_sections"] = list(
                lwr_info.get("sections") or []
            )
            info["actions"].append("leading_word_repetition_fix")

    if (
        flags.get("duplicate_sentence_issue")
        or flags.get("near_duplicate_paragraph_issue")
        or flags.get("section_repetition_issue")
    ):
        cleaned = _dedupe_consecutive_sentences(text)
        cleaned = _deduplicate_sentences(cleaned)
        cleaned = _merge_duplicate_canonical_sections(
            cleaned, include_health_rating=include_health_rating
        )
        if cleaned != text:
            text = cleaned
            info["changed"] = True
            info["actions"].append("repetition_cleanup")

    if flags.get("numbers_discipline_issue"):
        flagged_sections = set(flags.get("numbers_discipline_sections") or [])
        if not flagged_sections:
            flagged_sections = {"Executive Summary"}

        if "Executive Summary" in flagged_sections:
            updated, replaced_count = _scrub_executive_summary_numeric_density(
                text,
                target_length=target_length,
                quality_profile=quality_profile,
            )
            if replaced_count and updated != text:
                text = updated
                info["changed"] = True
                info["exec_numeric_scrub_replacements"] = int(replaced_count)
                info["generic_numeric_scrub_replacements"] = int(
                    info.get("generic_numeric_scrub_replacements", 0) or 0
                ) + int(replaced_count)
                info["actions"].append("exec_numeric_density_scrub")

        for section_title, action_name, info_key in (
            (
                "Financial Performance",
                "financial_performance_numeric_density_scrub",
                "perf_numeric_scrub_replacements",
            ),
            (
                "Management Discussion & Analysis",
                "mdna_numeric_density_scrub",
                "mdna_numeric_scrub_replacements",
            ),
            ("Risk Factors", "risk_numeric_density_scrub", None),
            ("Closing Takeaway", "closing_numeric_density_scrub", None),
        ):
            if section_title not in flagged_sections:
                continue
            updated, replaced_count = _scrub_section_numeric_density(
                text,
                section_title=section_title,
                target_length=target_length,
                quality_profile=quality_profile,
            )
            if replaced_count and updated != text:
                text = updated
                info["changed"] = True
                info["generic_numeric_scrub_replacements"] = int(
                    info.get("generic_numeric_scrub_replacements", 0) or 0
                ) + int(replaced_count)
                if info_key:
                    info[info_key] = int(replaced_count)
                info["actions"].append(action_name)

    if flags.get("bridge_issue"):
        bridged = _ensure_section_transition_handoffs(
            text,
            include_health_rating=include_health_rating,
            target_length=target_length,
        )
        if bridged != text:
            text = bridged
            info["changed"] = True
            info["actions"].append("section_transition_handoff_repair")

    closing_body = _extract_markdown_section_body(text, "Closing Takeaway")
    if closing_body:
        capped_closing, removed_sentences = (
            _cap_closing_takeaway_sentences_preserve_triggers(
                closing_body,
                budget_words=_closing_takeaway_budget_for_target(
                    target_length, include_health_rating=include_health_rating
                ),
            )
        )
        capped_closing = _normalize_closing_prose_spacing(capped_closing)
        if removed_sentences > 0 and capped_closing != closing_body:
            text = _replace_markdown_section_body(
                text, "Closing Takeaway", capped_closing
            )
            info["changed"] = True
            info["actions"].append("closing_sentence_cap")

    if info["changed"]:
        if generation_stats is not None:
            generation_stats.setdefault("editorial_repair_actions", []).extend(
                info["actions"]
            )
            generation_stats["editorial_repair_changed_text"] = True
            generation_stats["closing_parenthetical_removals"] = int(
                generation_stats.get("closing_parenthetical_removals", 0) or 0
            ) + int(info["closing_parenthetical_removals"])
            generation_stats["exec_numeric_scrub_replacements"] = int(
                generation_stats.get("exec_numeric_scrub_replacements", 0) or 0
            ) + int(info["exec_numeric_scrub_replacements"])
            generation_stats["leading_word_repetition_rewrites"] = int(
                generation_stats.get("leading_word_repetition_rewrites", 0) or 0
            ) + int(info.get("leading_word_repetition_rewrites", 0) or 0)
            if info.get("leading_word_repetition_fix_sections"):
                generation_stats["leading_word_repetition_fix_sections"] = list(
                    {
                        *(
                            generation_stats.get(
                                "leading_word_repetition_fix_sections", []
                            )
                            or []
                        ),
                        *(info.get("leading_word_repetition_fix_sections") or []),
                    }
                )
            if int(info.get("perf_numeric_scrub_replacements", 0) or 0) > 0:
                generation_stats["perf_numeric_scrub_replacements"] = int(
                    generation_stats.get("perf_numeric_scrub_replacements", 0) or 0
                ) + int(info["perf_numeric_scrub_replacements"])
            if int(info.get("mdna_numeric_scrub_replacements", 0) or 0) > 0:
                generation_stats["mdna_numeric_scrub_replacements"] = int(
                    generation_stats.get("mdna_numeric_scrub_replacements", 0) or 0
                ) + int(info["mdna_numeric_scrub_replacements"])
    return text, info


def _repair_brief_sections_deterministically(
    summary_text: str,
    *,
    missing_requirements: Optional[List[str]],
    calculated_metrics: Optional[Dict[str, Any]] = None,
    health_score_data: Optional[Dict[str, Any]] = None,
    risk_factors_excerpt: str = "",
    generation_stats: Optional[Dict[str, Any]] = None,
) -> Tuple[str, Dict[str, Any]]:
    text = (summary_text or "").strip()
    info: Dict[str, Any] = {
        "changed": False,
        "applied": False,
        "words_added": 0,
        "sections": [],
        "actions": [],
    }
    if not text:
        return summary_text, info

    brief_re = re.compile(
        r"the '([^']+)' section is too brief \((\d+) words\)\. expand it to at least (\d+) words",
        re.IGNORECASE,
    )
    parsed_targets: Dict[str, int] = {}
    for item in missing_requirements or []:
        match = brief_re.search(str(item or ""))
        if not match:
            continue
        section_title = str(match.group(1) or "").strip()
        if not section_title or section_title == "Key Metrics":
            continue
        min_words = int(match.group(3) or 0)
        if min_words <= 0:
            continue
        parsed_targets[section_title] = max(
            int(parsed_targets.get(section_title, 0) or 0),
            int(min_words),
        )

    if not parsed_targets:
        return summary_text, info

    for section_title, min_words in parsed_targets.items():
        body = _extract_markdown_section_body(text, section_title)
        if body is None:
            continue
        current_words = _count_words(body)
        if current_words >= int(min_words):
            continue

        attempts = 0
        section_changed = False
        while current_words < int(min_words) and attempts < 4:
            remaining_words = max(0, int(min_words) - int(current_words))
            extended_body, added_words = _extend_section_tail_clause_for_brief_repair(
                body,
                section_title=section_title,
                min_add_words=int(remaining_words),
            )
            if added_words > 0 and extended_body != body:
                info["words_added"] = int(info.get("words_added", 0) or 0) + int(
                    added_words
                )
                body = extended_body
                current_words = _count_words(body)
                section_changed = True
                attempts += 1
                continue

            addition = _section_balance_micro_top_up_sentence(
                section_title,
                max_words=int(remaining_words),
                existing_body=body,
            )
            if not addition:
                addition = _next_unique_section_balance_top_up_sentence(
                    body,
                    section_title=section_title,
                    attempt=attempts,
                    calculated_metrics=calculated_metrics,
                    health_score_data=health_score_data,
                    risk_factors_excerpt=risk_factors_excerpt or "",
                )
            if not addition:
                break

            updated_body = _append_section_balance_sentence(
                body,
                section_title=section_title,
                sentence=addition,
            )
            updated_words = _count_words(updated_body)
            if updated_words <= current_words:
                break

            info["words_added"] = int(info.get("words_added", 0) or 0) + int(
                updated_words - current_words
            )
            body = updated_body
            current_words = updated_words
            section_changed = True
            attempts += 1

        if not section_changed:
            continue
        text = _replace_markdown_section_body(text, section_title, body)
        info["changed"] = True
        info["applied"] = True
        info["sections"].append(section_title)

    if info["applied"]:
        info["sections"] = list(dict.fromkeys(info["sections"]))
        info["actions"].append("brief_section_top_up")
        if generation_stats is not None:
            generation_stats.setdefault("editorial_repair_actions", []).extend(
                info["actions"]
            )
            generation_stats["brief_section_top_up_words_added"] = int(
                generation_stats.get("brief_section_top_up_words_added", 0) or 0
            ) + int(info["words_added"])
            generation_stats["brief_section_top_up_sections"] = list(
                {
                    *(generation_stats.get("brief_section_top_up_sections", []) or []),
                    *(info["sections"] or []),
                }
            )

    return text, info


def _is_closing_trigger_sentence_for_balance_trim(sentence: str) -> bool:
    if not sentence:
        return False
    lowered = sentence.lower()
    if lowered.startswith("what must stay true") or lowered.startswith(
        "what breaks the thesis"
    ):
        return True
    if not re.search(r"\b(if|unless|would|trigger|flip|change)\b", lowered):
        return False
    if not re.search(
        r"(\$?\d+(?:\.\d+)?\s*(?:%|x|pp|b|m|bn|mm)?|\babove\b|\bbelow\b|\bat least\b|\bless than\b|\bmore than\b)",
        sentence,
        re.IGNORECASE,
    ):
        return False
    if not re.search(
        r"\b(next|quarter|quarters|month|months|year|years|period|periods|q[1-4]|fy\d{2})\b",
        sentence,
        re.IGNORECASE,
    ):
        return False
    return True


